                    <input type="number" min="5" max="200" value="${charEx.autoSumEvery||20}" data-el="sumEveryInput" data-npcid="${esc(contactId)}" style="width:60px;padding:4px 8px;border:1px solid rgba(0,0,0,.1);border-radius:8px;font-size:13px;outline:none;text-align:center;background:rgba(255,255,255,.9);"/>
