  try{
    var d = new Date(Number(ts||0));
    var y = d.getFullYear();
    var m = String(d.getMonth()+1).padStart(2,'0');
    var dd = String(d.getDate()).padStart(2,'0');
    var hh = String(d.getHours()).padStart(2,'0');
    var mm = String(d.getMinutes()).padStart(2,'0');
    return y + '-' + m + '-' + dd + ' ' + hh + ':' + mm;
  }catch(e){ return '—'; }
