          var descWords = (lm2.tags||[]).slice(0,3).map(function(t){ return tagDesc3[t]||''; }).filter(Boolean).join('，');
          var autoDesc = dn2+'，'+(descWords||'一个有趣的地方')+'。';
          if(descInp) descInp.value = autoDesc;
          lmOv.remove();
