// ★ 房间设置：角色房间的生活日志生成（独立于地图NPC日志）
async function _openRoomSettings(container, mapData, houseId, npcId, npcName){
  var savedPrompt = '';
  try{
    var uid = phoneGetChatUID();
    var rsCfg = phoneGetC(uid, 'room_settings_v1', {});
    savedPrompt = (rsCfg && rsCfg[houseId] && rsCfg[houseId].customPrompt) || '';
  }catch(e){}

  var logD = _mapLoadLog();
  var roomLogs = (logD.logs||[]).filter(function(l){ return l.npcId===npcId && l.period==='room'; });
  var logCount = roomLogs.length;

  var inner =
    '<div style="font-size:14px;font-weight:600;color:var(--ph-text);margin-bottom:4px;display:flex;align-items:center;gap:6px;">'+_roomUiIcon('house')+'<span>'+esc(npcName)+'的房间日志</span></div>' +
    '<div style="font-size:11px;color:var(--ph-text-sub);margin-bottom:12px;">当前已有 '+logCount+' 条房间动态</div>' +
    '<div style="font-size:11px;color:var(--ph-text-sub);margin-bottom:6px;">自定义生成提示词（可选）</div>' +
    '<textarea data-el="rsPrompt" rows="4" placeholder="留空使用默认，例如：重点描写角色的兴趣爱好和日常习惯，语气要细腻温柔…" style="width:100%;padding:8px 10px;border:1px solid var(--ph-glass-border,rgba(0,0,0,.1));border-radius:10px;font-size:12px;font-family:inherit;outline:none;resize:vertical;box-sizing:border-box;background:var(--ph-glass);color:var(--ph-text);line-height:1.6;">'+esc(savedPrompt)+'</textarea>' +
    '<button data-el="rsGenerate" style="width:100%;margin-top:10px;padding:11px;border-radius:12px;border:0;background:var(--ph-accent-grad,linear-gradient(135deg,#07c160,#06a050));color:#fff;font-size:13px;font-weight:600;cursor:pointer;">✦ 生成角色房间日志</button>' +
    '<div style="font-size:11px;color:var(--ph-text-sub);text-align:center;margin-top:6px;opacity:.6;">生成后从房间内点击家具发现</div>' +
    '<button data-el="rsClear" style="width:100%;margin-top:8px;padding:9px;border-radius:10px;border:1px solid rgba(231,76,60,.2);background:transparent;color:#e74c3c;font-size:12px;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:6px;">'+_roomUiIcon('trash')+'<span>清空房间日志</span></button>' +
    '<button data-el="rsClose" style="width:100%;margin-top:6px;padding:9px;border-radius:10px;border:1px solid var(--ph-glass-border,rgba(0,0,0,.08));background:transparent;font-size:12px;cursor:pointer;color:var(--ph-text-sub);">关闭</button>';

  var ov = (typeof _cpShowOverlay === 'function') ? _cpShowOverlay(inner) : null;
  if(!ov) return;
  ov.classList.add('mapRoomSettingsOverlay');
  var _rsModal = ov.querySelector('.wxCPModal');
  if(_rsModal) _rsModal.classList.add('mapRoomSettingsModal');

  ov.querySelector('[data-el="rsClose"]')?.addEventListener('click', function(){ ov.remove(); });

  ov.querySelector('[data-el="rsClear"]')?.addEventListener('click', function(){
    var ld2 = _mapLoadLog();
    ld2.logs = (ld2.logs||[]).filter(function(l){ return !(l.npcId===npcId && l.period==='room'); });
    _mapSaveLog(ld2);
    try{ toast('已清空房间日志'); }catch(e){}
    ov.remove();
  });

  ov.querySelector('[data-el="rsGenerate"]')?.addEventListener('click', async function(){
    var btn = this; btn.disabled=true; btn.textContent='生成中…';
    var customPrompt = (ov.querySelector('[data-el="rsPrompt"]')?.value||'').trim();
    // Save prompt
    try{
      var uid2 = phoneGetChatUID();
      var rsCfg2 = phoneGetC(uid2,'room_settings_v1',{});
      if(!rsCfg2[houseId]) rsCfg2[houseId]={};
      rsCfg2[houseId].customPrompt = customPrompt;
      phoneSetC(uid2,'room_settings_v1',rsCfg2);
    }catch(e){}

    try{
      var db3 = (typeof loadContactsDB==='function') ? loadContactsDB() : null;
      var npc3 = (db3 && typeof findContactById==='function') ? (findContactById(db3,npcId)||{name:npcName}) : {name:npcName};
      var charEx3 = (typeof _loadCharExtra==='function') ? _loadCharExtra(npcId) : {};
      var cs3 = (typeof _loadCharState==='function') ? _loadCharState(npcId) : null;
      var attrLine = '';
      if(cs3&&cs3.attrs){ var a=cs3.attrs; attrLine='当前状态：精力'+Math.round(a.energy||0)+' 心情'+Math.round(a.mood||0)+' 饱腹'+Math.round(a.hunger||0)+'\n'; }
      var mapD3 = _mapLoad();
      var house3 = mapD3 ? (mapD3.houses||[]).find(function(h){ return h.id===houseId; }) : null;
      var furnList = (house3&&house3.rooms&&house3.rooms.furniture) ?
        house3.rooms.furniture.filter(function(f3){ return f3.owned; }).map(function(f3){ return f3.type; }).join('、') : '';

      // ★ 用 buildSystemPrompt 获取完整角色上下文（含世界书/行为参数/性格/作息/总结/聊天记录等）
      var fullSysPrompt = '';
      try{ fullSysPrompt = buildSystemPrompt(npcId); }catch(e){}

      // ★ 最近聊天记录（线上+线下，权重9）——条数用用户在小手机设置里定的N
      var recentChatLines = '';
      try{
        var _ctxN = (typeof _getChatContextN==='function') ? _getChatContextN() : 10;
        var _ctxNOff = (typeof _getOfflineChatContextN==='function') ? _getOfflineChatContextN() : 5;
        var _onLog = _getLogForModeBranch(npcId,'online').slice(-_ctxN);
        var _offLog = _getLogForModeBranch(npcId,'offline').slice(-_ctxNOff);
        var _allRecent = _onLog.concat(_offLog).filter(function(m){ return m.role!=='system'&&!m.recalled; });
        if(_allRecent.length){
          recentChatLines = '【最近聊天记录（线上+线下，权重最高）】\n' +
            _allRecent.map(function(m){
              return (m.role==='me'?'用户':'你('+npcName+')')+': '+String(m.text||'').slice(0,100);
            }).join('\n');
        }
      }catch(e){}

      var sysP3 =
        (fullSysPrompt ? fullSysPrompt + '\n\n' : '') +
        (recentChatLines ? recentChatLines + '\n\n' : '') +
        '---\n' +
        '【任务：生成角色在家中的生活日志】\n' +
        '你现在要生成「'+npcName+'」独自在家时的生活动态日志。\n' +
        '要求：\n' +
        '- 严格贴合角色性格、口癖、生活习惯（从上方角色设定和聊天记录中提取）\n' +
        '- 体现角色真实的日常细节，不要泛泛而谈\n' +
        '- 如果聊天记录里有相关事件（如刚吃过火锅、刚见过用户），日志里可以自然呼应\n' +
        '- 只返回 JSON 数组，不要任何其他内容\n' +
        '格式：[{"action":"角色正在做什么（15字内，第一人称，具体生动）","emoji":"对应emoji（1个）","mood":"情绪词（轻松/专注/惬意等）","time_hint":"时间描述如早晨/傍晚"}]';

      var userM3 =
        attrLine+
        '房间家具：'+furnList+'。\n'+
        (customPrompt?'特别要求：'+customPrompt+'\n':'')+
        '请生成「'+npcName+'」在家中的4-6条生活动态日志，必须符合上方角色性格和近期经历。';

      var res3 = await PhoneAI.chat({
        system: sysP3,
        messages: [{role:'user',content:userM3}],
        channel:'background', maxTokens:600, timeout:60
      });
      if(!res3||!res3.ok) throw new Error(res3&&res3.error||'请求失败');
      var raw3 = String(res3.data||'').replace(/```json[\s\S]*?```|```[\s\S]*?```/g,function(m){return m.replace(/```json?/,'').replace(/```/,'');}).trim();
      var arr3 = JSON.parse((raw3.match(/\[[\s\S]*\]/)||['[]'])[0]);
      var now3 = Date.now();
      var logD3 = _mapLoadLog();
      var added3 = 0;
      arr3.forEach(function(item, idx){
        if(!item.action) return;
        logD3.logs.push({
          id:'log_room_ai_'+now3+'_'+idx, npcId:npcId, npcName:npcName,
          landmarkId:houseId, time:now3 - (arr3.length-1-idx)*1800000,
          period:'room', action:item.action,
          cost:0, statusEffect:{mood:3}, isAuto:true,
          emoji:item.emoji||'🏠', mood:item.mood, time_hint:item.time_hint
        });
        added3++;
      });
      if(logD3.logs.length>300) logD3.logs=logD3.logs.slice(-300);
      _mapSaveLog(logD3);
      try{ toast('✦ 已为'+esc(npcName||'角色')+'生成 '+added3+' 条房间日志，点击家具发现'); }catch(e){}
      ov.remove(); // 关闭面板，保持惊喜感
    }catch(e){
      try{ toast('生成失败: '+(e.message||e)); }catch(e2){}
      btn.disabled=false; btn.textContent='✦ 生成角色房间日志';
    }
  });
}

// ★ NPC 家具互动面板（前置声明）

async function _showNpcFurnPanel(container, mapData, houseId, npcId, npcName, furn, cat){
  // 先更新角色属性
  try{
    var cs2 = _loadCharState(npcId);
    if(cs2&&cs2.attrs){ for(var fk in (cat.fx||{})){ if(cs2.attrs[fk]!=null) cs2.attrs[fk]=_clampAttr(fk,cs2.attrs[fk]+(cat.fx[fk]||0)); } cs2.lastCalcAt=Date.now(); _saveCharState(npcId,cs2); }
  }catch(e){}

  // 隐藏物品提示
  var furnSecretTypes = {
    bed:'床头柜里可能藏着一本日记或私人信件',sofa:'沙发垫下有时会夹着随手写的便条',
    stove:'锅里残留的味道，冰箱上贴的便利贴',lamp:'床头灯旁的书签、夹在书里的字条',
    wardrobe:'衣柜最里面可能有珍藏的照片或旧物',tv:'电视机旁夹着一张电话号码',
    piano:'琴谱里夹着一首写给某人的曲子',plant:'花盆底部藏着一个小纸条',
    coffeetable:'茶几抽屉里有一叠没寄出的信',bookshelf:'书架最高处有一本特别的书'
  };
  var secretHint = furnSecretTypes[furn.type] || '这件家具旁可能藏着什么……';
  var npcAvSrc = (typeof phoneGetAvatar==='function') ? phoneGetAvatar(npcId) : '';
  var avH = npcAvSrc ? '<img src="'+esc(npcAvSrc)+'" style="width:100%;height:100%;object-fit:cover;border-radius:inherit;"/>' : esc((npcName||'?').charAt(0));
  var attrFx = []; var attrNames={mood:'心情',energy:'精力',health:'健康',hunger:'饱腹',fun:'娱乐'};
  for(var fk2 in (cat.fx||{})){ var v=cat.fx[fk2]; if(v>0) attrFx.push((attrNames[fk2]||fk2)+'+'+v); }

  var inner =
    // 头部
    '<div style="display:flex;align-items:center;gap:10px;margin-bottom:14px;">' +
      '<div style="width:44px;height:44px;border-radius:50%;overflow:hidden;background:rgba(0,0,0,.06);display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;">'+avH+'</div>' +
      '<div><div style="font-size:14px;font-weight:600;color:var(--ph-text);">'+esc(npcName)+'的'+esc(cat.label)+'</div>' +
      '<div style="font-size:11px;color:var(--ph-text-sub);margin-top:2px;display:flex;align-items:center;gap:6px;">'+_roomUiIcon(furn.type||cat.emoji)+'<span>'+(attrFx.join(' ')||cat.desc)+'</span></div></div>' +
    '</div>' +
    // 场景感描述
    '<div style="font-size:12px;line-height:1.7;color:var(--ph-text);padding:10px 12px;background:rgba(0,0,0,.02);border-radius:10px;margin-bottom:12px;">'+
      esc(npcName)+'常在这里'+(cat.desc||'休息')+'，也许留下了一些痕迹……'+
    '</div>' +
    // 两个发现按钮
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:8px;">' +
      '<button data-el="discoverLog" style="padding:11px 6px;border-radius:12px;border:0;background:var(--ph-glass,rgba(255,255,255,.85));border:1px solid var(--ph-glass-border,rgba(0,0,0,.08));font-size:12px;cursor:pointer;color:var(--ph-text);display:flex;align-items:center;justify-content:center;gap:5px;">'+_roomUiIcon('calendar')+'<span>查看动态</span></button>' +
      '<button data-el="discoverSecret" style="padding:11px 6px;border-radius:12px;border:0;background:rgba(243,156,18,.08);border:1px solid rgba(243,156,18,.2);font-size:12px;cursor:pointer;color:#b7800a;display:flex;align-items:center;justify-content:center;gap:5px;">'+_roomUiIcon('search')+'<span>发现秘密</span></button>' +
    '</div>' +
    // 动态区（隐藏）
    '<div data-el="logArea" style="display:none;margin-bottom:8px;">' +
      '<div style="font-size:10.5px;color:var(--ph-text-sub);margin-bottom:6px;opacity:.7;display:flex;align-items:center;gap:5px;">'+_roomUiIcon('calendar')+'<span>最近动态</span></div>' +
      '<div data-el="logList"></div>' +
      '<button data-el="genMore" style="width:100%;margin-top:6px;padding:8px;border-radius:10px;border:0;background:var(--ph-accent-grad,linear-gradient(135deg,#07c160,#06a050));color:#fff;font-size:12px;font-weight:600;cursor:pointer;">✦ AI 生成更多日志</button>' +
    '</div>' +
    // 秘密区（隐藏）
    '<div data-el="secretArea" style="display:none;margin-bottom:8px;padding:12px 14px;background:rgba(243,156,18,.05);border:1px solid rgba(243,156,18,.2);border-radius:12px;font-size:12px;color:var(--ph-text);line-height:1.7;"></div>' +
    '<button data-el="favSecret" style="display:none;width:100%;padding:9px;border-radius:10px;border:1px solid rgba(243,156,18,.25);background:rgba(243,156,18,.06);font-size:12px;cursor:pointer;color:#b7800a;margin-bottom:6px;display:flex;align-items:center;justify-content:center;gap:6px;">'+_roomUiIcon('bookmark')+'<span>收藏这个发现</span></button>' +
    '<button data-el="panelClose" style="width:100%;padding:9px;border-radius:10px;border:1px solid var(--ph-glass-border,rgba(0,0,0,.08));background:transparent;font-size:12px;cursor:pointer;color:var(--ph-text-sub);">关闭</button>';

  var ov = _cpShowOverlay(inner);
  ov.querySelector('[data-el="panelClose"]')?.addEventListener('click', function(){ ov.remove(); });

  // ★ 收藏秘密 → 存入我的收藏（type: room_secret）
  ov.querySelector('[data-el="favSecret"]')?.addEventListener('click', function(){
    try{
      var secretTxt = this._secretText || '';
      if(!secretTxt){ try{toast('没有可收藏的内容');}catch(e){} return; }
      var data = _loadFavorites();
      var favId = 'room_secret_'+npcId+'_'+cat.type+'_'+Date.now();
      // 检查近似重复
      for(var i=0;i<data.list.length;i++){
        if(data.list[i].content===secretTxt){
          try{toast('已在收藏中');}catch(e){} return;
        }
      }
      data.list.push({
        type: 'room_secret',
        content: secretTxt,
        tags: [npcName, cat.label, '房间秘密'],
        time: _now(),
        msgId: favId,
        from: npcName,
        npcId: npcId,
        furnType: cat.type,
        furnLabel: cat.label,
        furnEmoji: cat.emoji
      });
      _saveFavorites(data);
      this.textContent = '✅ 已收藏';
      this.disabled = true;
      try{toast('🔖 已收藏到「我的收藏」');}catch(e){}
    }catch(e){ try{toast('收藏失败');}catch(e2){} }
  });

  function buildLogHtml(logs){
    if(!logs||!logs.length) return '<div style="font-size:11px;color:rgba(20,24,28,.3);text-align:center;padding:8px 0;">暂无动态记录</div>';
    return logs.map(function(l){
      var t=l.time?new Date(l.time):null, ts=t?(t.getHours()<10?'0':'')+t.getHours()+':'+(t.getMinutes()<10?'0':'')+t.getMinutes():'';
      return '<div style="display:flex;align-items:center;gap:6px;padding:5px 0;border-bottom:1px solid rgba(0,0,0,.04);">' +
        '<span style="color:var(--ph-icon-inner-tint,var(--ph-text-sub));">'+_roomUiIcon(cat.type||l.emoji||cat.emoji||'search')+'</span>' +
        '<span style="font-size:11px;color:rgba(20,24,28,.75);flex:1;">'+esc(l.action||'')+'</span>' +
        '<span style="font-size:9px;color:rgba(20,24,28,.3);">'+ts+'</span></div>';
    }).join('');
  }

  // 查看动态
  ov.querySelector('[data-el="discoverLog"]')?.addEventListener('click', function(){
    var logArea = ov.querySelector('[data-el="logArea"]');
    var secretArea = ov.querySelector('[data-el="secretArea"]');
    if(logArea.style.display==='none'){
      var ld = _mapLoadLog();
      var logs = (ld.logs||[]).filter(function(l){return l.npcId===npcId;}).slice(-5).reverse();
      ov.querySelector('[data-el="logList"]').innerHTML = buildLogHtml(logs);
      logArea.style.display='block';
      if(secretArea) secretArea.style.display='none';
    } else { logArea.style.display='none'; }
  });

  // AI生成更多日志
  ov.querySelector('[data-el="genMore"]')?.addEventListener('click', async function(){
    var btn=this; btn.disabled=true; btn.textContent='生成中…';
    try{
      var charEx=_loadCharExtra(npcId);
      var sysP='你是角色「'+npcName+'」的生活模拟器。只返回 JSON 数组。\n格式：[{"action":"第一人称描述（15字内）","emoji":"emoji","mood":"情绪词"}]\n'+(charEx&&charEx.profile?'角色设定：'+charEx.profile.slice(0,300)+'\n':'');
      var userM='角色刚用了「'+cat.label+'」（'+cat.desc+'），生成3条接下来的生活动态。';
      var res=await PhoneAI.chat({system:sysP,messages:[{role:'user',content:userM}],channel:'background',maxTokens:400,timeout:30});
      if(!res||!res.ok) throw new Error(res&&res.error||'失败');
      var arr=JSON.parse((String(res.data||'').match(/\[[\s\S]*\]/)||['[]'])[0]);
      var now=Date.now(); var ld2=_mapLoadLog(); var added=0;
      arr.forEach(function(item){ if(!item.action) return;
        ld2.logs.push({id:'log_ai_'+now+'_'+added, npcId:npcId, npcName:npcName, landmarkId:houseId, time:now+added*120000, period:'room', action:item.action, cost:0, statusEffect:{mood:5}, isAuto:true, emoji:item.emoji||cat.emoji}); added++; });
      if(ld2.logs.length>200) ld2.logs=ld2.logs.slice(-200);
      _mapSaveLog(ld2);
      var allLogs=ld2.logs.filter(function(l){return l.npcId===npcId;}).slice(-6).reverse();
      ov.querySelector('[data-el="logList"]').innerHTML=buildLogHtml(allLogs);
      try{toast('✦ 已生成 '+added+' 条动态');}catch(e){}
    }catch(e){try{toast('生成失败: '+(e.message||e));}catch(e2){}}
    btn.disabled=false; btn.textContent='✦ AI 生成更多日志';
  });

  // 🔍 发现秘密（点击才触发，有惊喜感）
  ov.querySelector('[data-el="discoverSecret"]')?.addEventListener('click', async function(){
    var btn=this; btn.disabled=true; btn.textContent='正在探寻…';
    var secretArea=ov.querySelector('[data-el="secretArea"]');
    var logArea=ov.querySelector('[data-el="logArea"]');
    if(secretArea) secretArea.style.display='none';
    if(logArea) logArea.style.display='none';
    try{
      // ★ 用 buildSystemPrompt 获取完整角色上下文（世界书/行为参数/性格/作息/总结等）
      var fullSysSecret = '';
      try{ fullSysSecret = buildSystemPrompt(npcId); }catch(e){}

      // ★ 最近聊天记录（线上+线下，用用户设置的N条）
      var recentSecretLines = '';
      try{
        var _ctxNs = (typeof _getChatContextN==='function') ? _getChatContextN() : 10;
        var _ctxNsOff = (typeof _getOfflineChatContextN==='function') ? _getOfflineChatContextN() : 5;
        var _onLogS = _getLogForModeBranch(npcId,'online').slice(-_ctxNs);
        var _offLogS = _getLogForModeBranch(npcId,'offline').slice(-_ctxNsOff);
        var _allS = _onLogS.concat(_offLogS).filter(function(m){ return m.role!=='system'&&!m.recalled; });
        if(_allS.length){
          recentSecretLines = '【最近聊天记录（权重最高）】\n' +
            _allS.map(function(m){
              return (m.role==='me'?'用户':'你('+npcName+')')+': '+String(m.text||'').slice(0,100);
            }).join('\n');
        }
      }catch(e){}

      var sysP4 =
        (fullSysSecret ? fullSysSecret + '\n\n' : '') +
        (recentSecretLines ? recentSecretLines + '\n\n' : '') +
        '---\n' +
        '【任务：生成家具秘密发现场景】\n' +
        '玩家正在探索「'+npcName+'」家中的「'+cat.label+'」，发现了一个隐藏的秘密。\n' +
        '要求：\n' +
        '- 严格贴合角色性格和近期经历（从上方聊天记录和角色设定提取细节）\n' +
        '- 用第二人称视角叙述（"你发现……"），80-150字，直接叙述无需标题\n' +
        '- 秘密要有真实感和细节，能反映角色内心或生活习惯\n' +
        '- 如果近期有相关事件（如刚一起吃饭、某句话、某个约定），可以呼应\n' +
        '- 温馨感人或有趣的基调，不要刻意煽情';

      var userM4='玩家检视了「'+esc(npcName)+'」家中的「'+cat.label+'」。'+secretHint+'。请根据角色性格和近期经历写出发现场景。';
      var res4=await PhoneAI.chat({system:sysP4,messages:[{role:'user',content:userM4}],channel:'background',maxTokens:400,timeout:60});
      if(!res4||!res4.ok) throw new Error('请求失败');
      var txt=String(res4.data||'').trim().replace(/^["「『]|["」』]$/g,'');
      if(txt&&secretArea){
        secretArea.style.display='block';
        secretArea.innerHTML='<div style="font-size:11px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));font-weight:600;margin-bottom:6px;display:flex;align-items:center;gap:6px;">'+_roomUiIcon('search')+'<span>你发现了……</span></div><div style="font-size:12px;line-height:1.75;color:var(--ph-text);">'+esc(txt)+'</div>';
        // ★ 显示收藏按钮
        var favBtn = ov.querySelector('[data-el="favSecret"]');
        if(favBtn){
          favBtn.style.display='block';
          favBtn._secretText = txt;
        }
      }
    }catch(e){
      if(secretArea){secretArea.style.display='block';secretArea.innerHTML='<div style="font-size:12px;color:var(--ph-text-sub);text-align:center;padding:8px;">什么也没发现……也许下次会不同。</div>';}
    }
    btn.disabled=false; btn.textContent='🔍 发现秘密';
  });
}

// ========== Chibi 角色 SVG 生成器 ==========
function _chibiFurnSVG(opts){
  var g   = opts.gender     || 'female';
  var h   = opts.hairStyle  || (g==='female'?'f1':'m1');
  var hc  = opts.hairColor  || '#2A2832';
  var sc  = opts.skinColor  || '#FAEBD7';
  var cc  = opts.coatColor  || '#4A5A6A';
  var ears= opts.catEars !== false;
  var acc = opts.acc        || false;
  var of2 = opts.outfit     || 'o1';
  var scene = opts.scene    || null; // null|'sleep'|'eat'|'sit'
  var scale = opts.scale    || 0.55;

  function dk(hex,a){ a=a||30; var r=parseInt(hex.slice(1,3),16)-a,gr=parseInt(hex.slice(3,5),16)-a,b=parseInt(hex.slice(5,7),16)-a; return 'rgb('+Math.max(0,r)+','+Math.max(0,gr)+','+Math.max(0,b)+')'; }
  function lt(hex,a){ a=a||25; var r=Math.min(255,parseInt(hex.slice(1,3),16)+a),gr=Math.min(255,parseInt(hex.slice(3,5),16)+a),b=Math.min(255,parseInt(hex.slice(5,7),16)+a); return 'rgb('+r+','+gr+','+b+')'; }
  var ct2=dk(cc,20), sk2=dk(sc,15), isF=g==='female';

  // --- 后发 ---
  function hairBack(){
    var c2=dk(hc);
    if(g==='male') return '';
    var m={'f1':'<path d="M-38,-16 Q-42,0 -44,18 Q-46,36 -40,48 Q-34,56 -20,58 Q-8,60 0,58 Q8,60 20,58 Q34,56 40,48 Q46,36 44,18 Q42,0 38,-16Z" fill="'+c2+'"/>',
      'f2':'<path d="M-30,-14 Q-44,-10 -52,6 Q-56,24 -50,44 Q-44,58 -36,64 Q-28,62 -34,50 Q-42,34 -44,20 Q-44,6 -38,-4 Q-34,-10 -30,-12Z" fill="'+c2+'"/><path d="M30,-14 Q44,-10 52,6 Q56,24 50,44 Q44,58 36,64 Q28,62 34,50 Q42,34 44,20 Q44,6 38,-4 Q34,-10 30,-12Z" fill="'+c2+'"/>',
      'f3':'<path d="M-38,-16 Q-42,0 -44,18 Q-46,36 -40,48 Q-34,56 -20,58 Q-8,60 0,58 Q8,60 20,58 Q34,56 40,48 Q46,36 44,18 Q42,0 38,-16Z" fill="'+c2+'"/>',
      'f4':'', 'f5':''};
    return m[h]||m['f1'];
  }

  // --- 前发 ---
  function hairFront(){
    var c2=dk(hc);
    var map={
      'f1':'<path d="M-44,-22 Q-36,-44 0,-48 Q36,-44 44,-22 Q48,0 46,6 Q38,12 28,6 Q18,12 8,6 Q-2,12 -14,6 Q-26,12 -36,7 Q-44,4 -46,6 Q-48,0 -44,-22Z" fill="'+hc+'"/><path d="M-44,5 Q-46,16 -42,28 Q-38,34 -34,32 Q-38,24 -40,14 Q-42,6 -42,5Z" fill="'+c2+'"/><path d="M44,5 Q46,16 42,28 Q38,34 34,32 Q38,24 40,14 Q42,6 42,5Z" fill="'+c2+'"/>',
      'f2':'<path d="M-44,-22 Q-36,-44 0,-48 Q36,-44 44,-22 Q48,0 46,8 L-46,8 Q-48,0 -44,-22Z" fill="'+hc+'"/><path d="M-36,0 Q-30,-28 0,-32 Q30,-28 36,0 Q32,6 26,3 Q18,8 10,3 Q2,8 -6,3 Q-14,8 -22,3 Q-30,6 -36,0Z" fill="'+hc+'"/>',
      'f3':'<path d="M-44,-22 Q-36,-44 0,-48 Q36,-44 44,-22 Q48,0 46,10 L-46,10 Q-48,0 -44,-22Z" fill="'+hc+'"/><rect x="-36" y="4" width="72" height="6" fill="'+hc+'"/><path d="M-44,6 Q-46,20 -42,34 Q-38,42 -34,40 Q-38,32 -40,20 Q-42,10 -42,6Z" fill="'+c2+'"/><path d="M44,6 Q46,20 42,34 Q38,42 34,40 Q38,32 40,20 Q42,10 42,6Z" fill="'+c2+'"/>',
      'f4':'<path d="M-44,-22 Q-36,-44 0,-48 Q36,-44 44,-22 Q48,0 46,8 L-46,8 Q-48,0 -44,-22Z" fill="'+hc+'"/><polygon points="0,-4 -10,8 10,8" fill="'+sc+'"/><ellipse cx="-36" cy="11" rx="7" ry="6.5" fill="'+hc+'"/><ellipse cx="-36" cy="22" rx="6.5" ry="6" fill="'+c2+'"/><ellipse cx="-36" cy="33" rx="6" ry="6" fill="'+hc+'"/><ellipse cx="-36" cy="43" rx="5.5" ry="5.5" fill="'+c2+'"/><ellipse cx="-36" cy="53" rx="5" ry="5" fill="'+hc+'"/><circle cx="-36" cy="62" r="4" fill="'+lt(hc,40)+'" stroke="'+dk(hc,10)+'" stroke-width="0.5"/><ellipse cx="36" cy="11" rx="7" ry="6.5" fill="'+hc+'"/><ellipse cx="36" cy="22" rx="6.5" ry="6" fill="'+c2+'"/><ellipse cx="36" cy="33" rx="6" ry="6" fill="'+hc+'"/><ellipse cx="36" cy="43" rx="5.5" ry="5.5" fill="'+c2+'"/><ellipse cx="36" cy="53" rx="5" ry="5" fill="'+hc+'"/><circle cx="36" cy="62" r="4" fill="'+lt(hc,40)+'" stroke="'+dk(hc,10)+'" stroke-width="0.5"/>',
      'f5':'<path d="M0,-48 Q-36,-44 -44,-22 Q-48,-2 -46,14 Q-42,28 -36,30 Q-30,28 -32,18 Q-36,6 -36,0 L36,0 Q36,6 32,18 Q30,28 36,30 Q42,28 46,14 Q48,-2 44,-22 Q36,-44 0,-48Z" fill="'+hc+'"/><path d="M-34,0 Q-28,-28 0,-32 Q28,-28 34,0 Q30,6 24,3 Q16,8 8,3 Q0,8 -8,3 Q-16,8 -24,3 Q-30,6 -34,0Z" fill="'+hc+'"/>',
      'm1':'<path d="M-42,-22 Q-34,-44 0,-48 Q34,-44 42,-22 Q46,-2 42,10 L-42,10 Q-46,-2 -42,-22Z" fill="'+hc+'"/><path d="M-36,-4 Q-30,-30 0,-34 Q30,-30 36,-4 Q32,2 26,-1 Q18,4 10,-1 Q2,4 -6,-1 Q-14,4 -22,-1 Q-30,2 -36,-4Z" fill="'+hc+'"/><path d="M-38,4 Q-42,14 -36,20 Q-32,14 -36,6Z" fill="'+c2+'"/><path d="M38,4 Q42,14 36,20 Q32,14 36,6Z" fill="'+c2+'"/>',
      'm2':'<path d="M-40,-18 Q-36,-42 -8,-45 Q8,-47 22,-44 Q36,-38 40,-18 Q43,-4 40,10 L-40,10 Q-43,-4 -40,-18Z" fill="'+hc+'"/><path d="M-38,10 Q-40,-2 -20,-12 Q-8,-16 2,10Z" fill="'+sc+'"/><path d="M-38,-20 L-10,-20 Q-20,2 -36,10Z" fill="'+c2+'"/><path d="M6,10 Q4,-12 18,-18 Q28,-8 30,10 Q22,4 12,10Z" fill="'+hc+'"/><path d="M-38,6 Q-42,12 -39,18 Q-35,12 -36,8Z" fill="'+c2+'"/><path d="M38,6 Q42,12 39,18 Q35,12 36,8Z" fill="'+c2+'"/>',
      'm3':'<path d="M-38,-20 Q-34,-44 -10,-46 Q-4,-48 0,-46 Q4,-50 12,-46 Q30,-42 38,-18 Q42,-4 38,8 L-38,8 Q-42,-4 -38,-20Z" fill="'+hc+'"/><path d="M-22,8 Q-24,-12 0,-18 Q24,-12 22,8Z" fill="'+sc+'"/><path d="M22,8 Q28,-16 8,-22 Q4,-10 0,8Z" fill="'+hc+'"/><path d="M28,8 Q38,-8 18,-20 Q12,-8 8,8Z" fill="'+c2+'"/><path d="M-36,6 Q-40,12 -37,18 Q-33,12 -34,8Z" fill="'+c2+'"/><path d="M36,6 Q40,12 37,18 Q33,12 34,8Z" fill="'+hc+'"/>',
      'm4':'<path d="M-36,-24 Q-26,-42 0,-46 Q26,-42 36,-24 Q40,-6 36,8 L-36,8 Q-40,-6 -36,-24Z" fill="'+hc+'"/><path d="M-28,-4 Q-16,-36 6,-40 Q28,-36 34,-8 L28,2 Q22,-8 14,0 Q6,-10 -2,0 Q-10,-8 -18,0 Q-24,-6 -26,0Z" fill="'+hc+'"/><path d="M-32,2 Q-34,10 -28,14 Q-26,8 -28,4Z" fill="'+c2+'"/><path d="M32,2 Q34,10 28,14 Q26,8 28,4Z" fill="'+c2+'"/>',
      'm5':'<path d="M-40,-22 Q-30,-44 0,-48 Q30,-44 40,-22 Q44,-2 40,12 L-40,12 Q-44,-2 -40,-22Z" fill="'+hc+'"/><polygon points="0,-4 -10,12 10,12" fill="'+sc+'"/><path d="M-38,8 Q-42,16 -39,22 Q-35,16 -36,12Z" fill="'+c2+'"/><path d="M38,8 Q42,16 39,22 Q35,16 36,12Z" fill="'+c2+'"/>'
    };
    return map[h]||map[isF?'f1':'m1'];
  }

  // --- 身体核心 SVG ---
  function chibiCore(){
    var legsHidden = (scene==='sit'||scene==='sleep');
    var armClass = isF ? 'crm-arm-l' : 'crm-male-arm-l';
    var armClassR = isF ? 'crm-arm-r' : 'crm-male-arm-r';
    var out = '';
    // 影子
    out += '<ellipse class="crm-shadow" cx="0" cy="78" rx="20" ry="7" fill="rgba(130,140,120,0.12)"/>';
    out += '<g class="crm-body">';
    // 尾巴
    if(ears) out += '<g class="crm-tail"><path d="M12,40 Q28,34 34,22 Q38,10 32,4" fill="none" stroke="'+dk(hc,10)+'" stroke-width="4" stroke-linecap="round"/><circle cx="32" cy="3" r="3" fill="'+hc+'"/></g>';
    // 后发
    out += hairBack();
    // 鞋
    if(!legsHidden) out += '<ellipse class="crm-leg-l" cx="0" cy="0" rx="5.5" ry="4" fill="#2A2520"/><ellipse class="crm-leg-r" cx="0" cy="0" rx="5.5" ry="4" fill="#2A2520"/>';
    // 身体
    if(isF){
      out += '<rect x="-15" y="34" width="30" height="22" rx="7" fill="'+cc+'"/>';
      out += '<path d="M-4,34 L0,41 L4,34" fill="none" stroke="rgba(255,255,255,0.5)" stroke-width="1.5" stroke-linecap="round"/>';
      if(of2==='o2') out += '<path d="M-12,34 L0,44 L12,34" fill="none" stroke="rgba(255,255,255,0.4)" stroke-width="2" stroke-linecap="round"/>';
      if(of2==='o3') out += '<rect x="-8" y="46" width="16" height="5" rx="2.5" fill="'+ct2+'" opacity="0.4"/>';
      var skH = of2==='o3'?'56':'60', skB = of2==='o3'?'58':'64';
      if(!legsHidden){
        out += '<path d="M-16,52 Q-18,'+skH+' -14,'+skB+' L14,'+skB+' Q18,'+skH+' 16,52Z" fill="'+ct2+'"/>';
        out += '<rect x="-11" y="'+(of2==='o3'?56:62)+'" width="8" height="'+(of2==='o3'?14:12)+'" rx="4" fill="'+cc+'"/>';
        out += '<rect x="3" y="'+(of2==='o3'?56:62)+'" width="8" height="'+(of2==='o3'?14:12)+'" rx="4" fill="'+ct2+'"/>';
      }
    } else {
      out += '<rect x="-15" y="34" width="30" height="24" rx="7" fill="'+cc+'"/>';
      out += '<path d="M-4,34 L0,41 L4,34" fill="none" stroke="rgba(255,255,255,0.5)" stroke-width="1.5" stroke-linecap="round"/>';
      if(of2==='o2') out += '<line x1="0" y1="34" x2="0" y2="58" stroke="'+ct2+'" stroke-width="1.5"/>';
      if(of2==='o3') out += '<rect x="-10" y="38" width="20" height="3" rx="1.5" fill="rgba(255,255,255,0.25)"/>';
      if(!legsHidden){
        out += '<rect x="-10" y="54" width="8" height="16" rx="4" fill="'+(of2==='o2'?'#3A3A44':cc)+'"/>';
        out += '<rect x="2" y="54" width="8" height="16" rx="4" fill="'+(of2==='o2'?'#2E2E38':ct2)+'"/>';
      }
    }
    // 手臂
    out += '<g class="'+armClass+'"><rect x="-4" y="0" width="7" height="14" rx="3.5" fill="'+cc+'" transform="translate(-15,36)"/><circle cx="0" cy="15" r="4" fill="'+sc+'" stroke="'+sk2+'" stroke-width="0.4" transform="translate(-15,36)"/></g>';
    out += '<g class="'+armClassR+'"><rect x="-3" y="0" width="7" height="14" rx="3.5" fill="'+ct2+'" transform="translate(15,36)"/><circle cx="0" cy="15" r="4" fill="'+sc+'" stroke="'+sk2+'" stroke-width="0.4" transform="translate(15,36)"/></g>';
    // 头
    out += '<circle cx="0" cy="0" r="38" fill="'+sc+'" stroke="'+sk2+'" stroke-width="0.8"/>';
    // 睡觉闭眼
    if(scene==='sleep'){
      out += '<rect x="-27" y="6" width="19" height="18" rx="3" fill="'+sc+'"/><rect x="8" y="6" width="19" height="18" rx="3" fill="'+sc+'"/>';
      out += '<path d="M-26,13 Q-18,20 -10,13" fill="none" stroke="#1A1518" stroke-width="2.5" stroke-linecap="round"/>';
      out += '<path d="M9,13 Q17,20 25,13" fill="none" stroke="#1A1518" stroke-width="2.5" stroke-linecap="round"/>';
    }
    // 前发
    out += hairFront();
    // 猫耳
    if(ears){
      out += '<path d="M-24,-32 L-34,-56 L-12,-38Z" fill="'+hc+'" stroke="'+dk(hc,20)+'" stroke-width="0.8" stroke-linejoin="round"/><path d="M-23,-34 L-31,-52 L-14,-38Z" fill="#E8BFB8"/>';
      out += '<path d="M24,-32 L34,-56 L12,-38Z" fill="'+hc+'" stroke="'+dk(hc,20)+'" stroke-width="0.8" stroke-linejoin="round"/><path d="M23,-34 L31,-52 L14,-38Z" fill="#E8BFB8"/>';
    }
    // 装饰
    if(acc&&isF){
      out += '<path d="M-36,-10 A 40,40 0 0,1 36,-10" fill="none" stroke="'+dk(cc,10)+'" stroke-width="7" stroke-linecap="round"/>';
      out += '<path d="M-36,-10 A 40,40 0 0,1 36,-10" fill="none" stroke="'+lt(cc,20)+'" stroke-width="3" stroke-linecap="round"/>';
      out += '<circle cx="-36" cy="-10" r="5" fill="'+cc+'"/><circle cx="36" cy="-10" r="5" fill="'+cc+'"/>';
    }
    if(acc&&!isF){
      out += '<path d="M-38,-18 Q-32,-50 0,-54 Q32,-50 38,-18 Q20,-14 0,-13 Q-20,-14 -38,-18Z" fill="'+cc+'"/>';
      out += '<path d="M-38,-18 Q-10,-22 0,-21 Q10,-22 20,-20 Q10,-12 -38,-18Z" fill="'+dk(cc,15)+'"/>';
      out += '<ellipse cx="0" cy="-54" rx="5" ry="3" fill="'+dk(cc,20)+'"/><circle cx="0" cy="-54" r="2.5" fill="'+lt(cc,20)+'"/>';
    }
    // 眼睛
    if(scene!=='sleep'){
      out += '<rect x="-25" y="8" width="15" height="15" rx="4.5" fill="#1A1518"/><rect x="10" y="8" width="15" height="15" rx="4.5" fill="#1A1518"/>';
      out += '<rect x="-23" y="9.5" width="4" height="5.5" rx="2" fill="white"/><rect x="12" y="9.5" width="4" height="5.5" rx="2" fill="white"/>';
      out += '<circle cx="-15" cy="19" r="1.2" fill="white" opacity="0.3"/><circle cx="20" cy="19" r="1.2" fill="white" opacity="0.3"/>';
      out += '<g class="crm-blink"><rect x="-25" y="8" width="15" height="15" rx="4.5" fill="'+sc+'"/><rect x="10" y="8" width="15" height="15" rx="4.5" fill="'+sc+'"/></g>';
    }
    out += '<path d="M-3,29 Q-1,31.5 0,30 Q1,31.5 3,29" fill="none" stroke="'+dk(sc,50)+'" stroke-width="1" stroke-linecap="round"/>';
    out += '<ellipse cx="-29" cy="20" rx="6" ry="3.5" fill="rgba(240,150,130,0.18)"/><ellipse cx="29" cy="20" rx="6" ry="3.5" fill="rgba(240,150,130,0.18)"/>';
    out += '</g>'; // chibi-body
    return out;
  }

  // --- 场景包装 ---
  var sceneHtml = '';
  if(scene==='sleep'){
    sceneHtml = '<g transform="rotate(-90) translate(-4,0)">'+chibiCore()+'</g>';
    sceneHtml += '<text class="crm-zzz-a" x="68" y="-8" font-size="9" font-weight="bold" fill="#A8B8A8">z</text>';
    sceneHtml += '<text class="crm-zzz-b" x="74" y="-22" font-size="12" font-weight="bold" fill="#A8B8A8">z</text>';
    sceneHtml += '<text class="crm-zzz-c" x="80" y="-38" font-size="16" font-weight="bold" fill="#A8B8A8">Z</text>';
  } else if(scene==='eat'){
    sceneHtml = chibiCore();
    sceneHtml += '<ellipse cx="0" cy="56" rx="13" ry="5.5" fill="#E8CCA8"/><path d="M-13,54 Q-10,64 0,66 Q10,64 13,54Z" fill="#F0D8B8"/><ellipse cx="0" cy="53" rx="12" ry="4" fill="white"/>';
    sceneHtml += '<path class="crm-steam-a" d="M-5,48 Q-7,43 -5,39" fill="none" stroke="#C8C0B0" stroke-width="1.5" stroke-linecap="round"/>';
    sceneHtml += '<path class="crm-steam-b" d="M0,47 Q2,42 0,38" fill="none" stroke="#C8C0B0" stroke-width="1.5" stroke-linecap="round"/>';
    sceneHtml += '<path class="crm-steam-c" d="M5,48 Q7,43 5,39" fill="none" stroke="#C8C0B0" stroke-width="1.5" stroke-linecap="round"/>';
    sceneHtml += '<g class="crm-chop"><line x1="14" y1="36" x2="4" y2="55" stroke="#A08060" stroke-width="1.8" stroke-linecap="round"/><line x1="18" y1="36" x2="8" y2="55" stroke="#A08060" stroke-width="1.8" stroke-linecap="round"/></g>';
  } else if(scene==='sit'){
    sceneHtml = '<rect x="18" y="10" width="6" height="42" rx="3" fill="#C8A880"/><rect x="-24" y="46" width="48" height="7" rx="3.5" fill="#C8A880"/><rect x="-20" y="52" width="4" height="22" rx="2" fill="#B89870"/><rect x="16" y="52" width="4" height="22" rx="2" fill="#B89870"/>';
    sceneHtml += chibiCore();
    sceneHtml += '<rect x="-13" y="52" width="26" height="25" fill="rgba(232,232,224,0)"/>';
    sceneHtml += '<rect x="-13" y="50" width="11" height="8" rx="4" fill="'+cc+'"/><rect x="2" y="50" width="11" height="8" rx="4" fill="'+ct2+'"/>';
    sceneHtml += '<g class="crm-sit-l"><rect x="-10" y="55" width="8" height="10" rx="4" fill="'+cc+'"/><ellipse cx="-6" cy="66" rx="5" ry="3" fill="#2A2520"/></g>';
    sceneHtml += '<g class="crm-sit-r"><rect x="2" y="55" width="8" height="10" rx="4" fill="'+ct2+'"/><ellipse cx="6" cy="66" rx="5" ry="3" fill="#2A2520"/></g>';
  } else {
    sceneHtml = chibiCore();
  }

  var uid = 'crm'+(Date.now()%100000);
  var css = '<style>@keyframes '+uid+'-float{0%,100%{transform:translateY(0)}50%{transform:translateY(-2.5px)}}@keyframes '+uid+'-shadow{0%,100%{transform:scaleX(1);opacity:0.12}50%{transform:scaleX(0.92);opacity:0.09}}@keyframes '+uid+'-blink{0%,90%,100%{transform:scaleY(0)}94%,96%{transform:scaleY(1)}}@keyframes '+uid+'-tail{0%,100%{transform:rotate(0deg)}40%{transform:rotate(18deg)}70%{transform:rotate(-10deg)}}@keyframes '+uid+'-arm-l{0%,100%{transform:rotate(-10deg)}50%{transform:rotate(-26deg)}}@keyframes '+uid+'-arm-r{0%,100%{transform:rotate(10deg)}50%{transform:rotate(26deg)}}@keyframes '+uid+'-male-l{0%,100%{transform:rotate(-8deg)}50%{transform:rotate(-14deg)}}@keyframes '+uid+'-male-r{0%,100%{transform:rotate(8deg)}50%{transform:rotate(14deg)}}@keyframes '+uid+'-leg-l{0%,100%{transform:translate(-6px,73px)}50%{transform:translate(-9px,70px)}}@keyframes '+uid+'-leg-r{0%,100%{transform:translate(6px,73px)}50%{transform:translate(9px,70px)}}@keyframes '+uid+'-zzz{0%{opacity:0;transform:translate(0,0)scale(0.5)}15%{opacity:1}100%{opacity:0;transform:translate(-6px,-32px)scale(1)}}@keyframes '+uid+'-steam{0%{opacity:0;transform:translateY(0)}20%{opacity:0.7}100%{opacity:0;transform:translateY(-16px)}}@keyframes '+uid+'-chop{0%,100%{transform:rotate(-5deg)}45%{transform:rotate(-32deg)}}@keyframes '+uid+'-sit{0%,100%{transform:rotate(0deg)}50%{transform:rotate(4deg)}}@keyframes '+uid+'-hairL{0%,100%{transform:rotate(0deg)skewX(0)}30%{transform:rotate(-2deg)skewX(-3deg)}60%{transform:rotate(1deg)skewX(2deg)}}@keyframes '+uid+'-hairR{0%,100%{transform:rotate(0deg)skewX(0)}30%{transform:rotate(2deg)skewX(3deg)}60%{transform:rotate(-1deg)skewX(-2deg)}}@keyframes '+uid+'-hairB{0%,100%{transform:skewX(0)}40%{transform:skewX(-2deg)}70%{transform:skewX(1.5deg)}}.crm-body{animation:'+uid+'-float 2.6s ease-in-out infinite}.crm-shadow{transform-origin:0 78px;animation:'+uid+'-shadow 2.6s ease-in-out infinite}.crm-blink{transform-origin:0 8px;animation:'+uid+'-blink 4s ease-in-out infinite}.crm-tail{transform-origin:12px 40px;animation:'+uid+'-tail 2s ease-in-out infinite}.crm-arm-l{transform-origin:-15px 36px;animation:'+uid+'-arm-l 0.7s ease-in-out infinite}.crm-arm-r{transform-origin:15px 36px;animation:'+uid+'-arm-r 0.7s ease-in-out infinite}.crm-male-arm-l{transform-origin:-15px 36px;animation:'+uid+'-male-l 1.8s ease-in-out infinite}.crm-male-arm-r{transform-origin:15px 36px;animation:'+uid+'-male-r 1.8s ease-in-out infinite;animation-delay:-0.9s}.crm-leg-l{animation:'+uid+'-leg-l 0.7s ease-in-out infinite}.crm-leg-r{animation:'+uid+'-leg-r 0.7s ease-in-out infinite;animation-delay:-0.35s}.crm-zzz-a{animation:'+uid+'-zzz 2.2s ease-out infinite}.crm-zzz-b{animation:'+uid+'-zzz 2.2s ease-out 0.75s infinite}.crm-zzz-c{animation:'+uid+'-zzz 2.2s ease-out 1.5s infinite}.crm-steam-a{animation:'+uid+'-steam 1.6s ease-out infinite}.crm-steam-b{animation:'+uid+'-steam 1.6s ease-out 0.55s infinite}.crm-steam-c{animation:'+uid+'-steam 1.6s ease-out 1.1s infinite}.crm-chop{transform-origin:14px 42px;animation:'+uid+'-chop 0.9s ease-in-out infinite}.crm-sit-l{transform-origin:-6px 52px;animation:'+uid+'-sit 2.4s ease-in-out infinite}.crm-sit-r{transform-origin:6px 52px;animation:'+uid+'-sit 2.4s ease-in-out infinite;animation-delay:-1.2s}.hair-side-l{transform-origin:-38px 0;animation:'+uid+'-hairL 3.2s ease-in-out infinite}.hair-side-r{transform-origin:38px 0;animation:'+uid+'-hairR 3.2s ease-in-out infinite}.hair-back{transform-origin:0 0;animation:'+uid+'-hairB 3.8s ease-in-out infinite}</style>';

  var viewBox = scene==='sleep' ? '-110 -55 220 130' : '-80 -80 160 185';
  var vw = scene==='sleep' ? 150 : 120;
  var vh = scene==='sleep' ? 100 : 150;

  return '<svg viewBox="'+viewBox+'" width="'+(vw*scale)+'" height="'+(vh*scale)+'" xmlns="http://www.w3.org/2000/svg" style="overflow:visible;">'+css+sceneHtml+'</svg>';
}

function _getChibiSettings(npcId){
  return _phLoad('chibi_'+String(npcId), {
    enabled: false,
    gender:'female', hairStyle:'f1', hairColor:'#2A2832',
    skinColor:'#FAEBD7', coatColor:'#4A5A6A',
    catEars:true, acc:false, outfit:'o1',
    posX: null, posY: null, scale: 0.42
  });
}
function _saveChibiSettings(npcId, data){ _phSave('chibi_'+String(npcId), data); }

function _getChibiScene(npcId){
  try{
    var bx = (typeof _loadCharBehavior==='function') ? _loadCharBehavior(npcId) : null;
    var doing = bx && bx.doing ? String(bx.doing) : '';
    // 读属性值
    var stats = (typeof catchUpStats==='function') ? catchUpStats(npcId) : null;
    var energy  = stats && stats.attrs ? (stats.attrs.energy  || 0) : 0;
    var hunger  = stats && stats.attrs ? (stats.attrs.hunger  || stats.attrs.satiety || 0) : 0;
    var h = new Date().getHours();

    // 睡觉：精力极低(<20) / doing含睡/休息/躺 / 深夜凌晨
    if(energy < 20 || /睡|休息|躺|床/.test(doing) || h>=23 || h<7) return 'sleep';
    // 吃饭：饱腹低(<30) / doing含吃/饭/餐/做菜
    if(hunger < 30 || /吃|饭|餐|做菜|厨/.test(doing) || h===8||h===12||h===19) return 'eat';
    // 坐着：doing含坐/看书/读/玩/游戏/电脑/手机
    if(/坐|看书|阅读|读书|玩|游戏|电脑|手机|沙发/.test(doing)) return 'sit';
  }catch(e){}
  return null; // 站立
}

function _openChibiEditor(container, npcId, npcName, onSave){
  var cfg = _getChibiSettings(npcId);
  var HC=['#2A2832','#8B7355','#E8D5A0','#C45555','#7B68AE','#E89BAE','#3A5566','#E8E4E0','#5A8A6A','#D49055'];
  var SKC=['#FAEBD7','#F5DEB3','#DEB887','#C8A882','#A0785A'];
  var CTC=['#4A5A6A','#2A2832','#F0EDE8','#B84444','#5A7A5A','#D4949E','#8B7355','#4466AA','#D4B44A'];
  // 发型列表按性别
  var FEMALE_HAIRS=[{id:'f1',l:'长发'},{id:'f2',l:'双马尾'},{id:'f3',l:'直刘海'},{id:'f4',l:'麻花辫'},{id:'f5',l:'波波头'}];
  var MALE_HAIRS  =[{id:'m1',l:'蓬松'},{id:'m2',l:'偏分'},{id:'m3',l:'韩式'},{id:'m4',l:'呆毛'},{id:'m5',l:'中分'}];

  function swatch(colors, val, key){
    return colors.map(function(c){
      return '<div data-cfgkey="'+key+'" data-cfgval="'+c+'" style="width:22px;height:22px;border-radius:50%;background:'+c+';cursor:pointer;border:'+(val===c?'2.5px solid #6A9A5A':'1.5px solid rgba(0,0,0,.08)')+';display:inline-block;margin:2px;"></div>';
    }).join('');
  }
  function btn(val, cur, key, label){
    return '<button data-cfgkey="'+key+'" data-cfgval="'+val+'" style="padding:4px 8px;border-radius:6px;font-size:10px;cursor:pointer;border:'+(cur===val?'2px solid #7AAA6A':'1.5px solid rgba(0,0,0,.1)')+';background:'+(cur===val?'rgba(122,170,106,.06)':'white')+';color:'+(cur===val?'#5A8A4A':'#999')+';margin:2px;">'+label+'</button>';
  }
  function hairButtons(gender, curHair){
    var list = gender==='male' ? MALE_HAIRS : FEMALE_HAIRS;
    return list.map(function(s){ return btn(s.id, curHair, 'hairStyle', s.l); }).join('');
  }

  var inner = '<div style="font-size:13px;font-weight:600;margin-bottom:10px;">👤 房间角色设置</div>'
    +'<div style="margin-bottom:10px;padding:10px;background:rgba(7,193,96,.04);border-radius:10px;border:1px solid rgba(7,193,96,.12);">'
    +'<label style="display:flex;align-items:center;gap:8px;font-size:12px;cursor:pointer;">'
    +'<input type="checkbox" data-cfgkey="enabled" '+(cfg.enabled?'checked':'')+' style="width:16px;height:16px;accent-color:#07c160;"> 在房间里显示角色</label></div>'
    +'<div style="margin-bottom:6px;">'
    +btn('female',cfg.gender,'gender','♀ 女生')+btn('male',cfg.gender,'gender','♂ 男生')
    +'</div>'
    +'<div data-el="hairBtns" style="margin-bottom:8px;">'+hairButtons(cfg.gender, cfg.hairStyle)+'</div>'
    +'<div style="font-size:10px;color:rgba(20,24,28,.4);margin-bottom:3px;">发色</div><div style="margin-bottom:8px;">'+swatch(HC,cfg.hairColor,'hairColor')+'</div>'
    +'<div style="font-size:10px;color:rgba(20,24,28,.4);margin-bottom:3px;">肤色</div><div style="margin-bottom:8px;">'+swatch(SKC,cfg.skinColor,'skinColor')+'</div>'
    +'<div style="font-size:10px;color:rgba(20,24,28,.4);margin-bottom:3px;">衣服颜色</div><div style="margin-bottom:8px;">'+swatch(CTC,cfg.coatColor,'coatColor')+'</div>'
    +'<div style="margin-bottom:8px;">'
    +'<label style="font-size:11px;cursor:pointer;margin-right:12px;"><input type="checkbox" data-cfgkey="catEars" '+(cfg.catEars?'checked':'')+' style="accent-color:#07c160;"> 🐱 猫耳</label>'
    +'<label style="font-size:11px;cursor:pointer;"><input type="checkbox" data-cfgkey="acc" '+(cfg.acc?'checked':'')+' style="accent-color:#07c160;"> 💎 装饰</label>'
    +'</div>'
    +'<div style="margin-bottom:10px;font-size:11px;color:rgba(20,24,28,.4);">动画根据doing和精力/饱腹自动切换（睡觉/吃饭/坐着/站立）</div>'
    +'<div style="display:flex;gap:8px;">'
    +'<button data-act="chibiSave" style="flex:1;padding:10px;border-radius:10px;border:0;background:var(--ph-accent,#07c160);color:#fff;font-size:13px;font-weight:600;cursor:pointer;">保存</button>'
    +'<button data-act="chibiCancel" style="padding:10px 16px;border-radius:10px;border:1px solid rgba(0,0,0,.08);background:rgba(255,255,255,.9);font-size:13px;cursor:pointer;color:rgba(20,24,28,.6);">取消</button>'
    +'</div>';

  var ov = _cpShowOverlay(inner);
  ov.addEventListener('click', function(e){
    var t = e.target;
    var key = t.getAttribute('data-cfgkey');
    if(key){
      if(t.type==='checkbox'){ cfg[key] = t.checked; }
      else {
        cfg[key] = t.getAttribute('data-cfgval');
        // 切换性别时刷新发型按钮
        if(key==='gender'){
          var defH = cfg.gender==='male' ? 'm1' : 'f1';
          cfg.hairStyle = defH;
          var hairBtnsEl = ov.querySelector('[data-el="hairBtns"]');
          if(hairBtnsEl) hairBtnsEl.innerHTML = hairButtons(cfg.gender, cfg.hairStyle);
        }
        // 更新同组按钮高亮
        ov.querySelectorAll('[data-cfgkey="'+key+'"]').forEach(function(b){
          if(b.type==='checkbox') return;
          var on = b.getAttribute('data-cfgval')===cfg[key];
          b.style.border = on?'2px solid #7AAA6A':'1.5px solid rgba(0,0,0,.1)';
          b.style.color  = on?'#5A8A4A':'#999';
          b.style.background = on?'rgba(122,170,106,.06)':'white';
        });
      }
    }
    if(t.getAttribute('data-act')==='chibiSave'){ _saveChibiSettings(npcId, cfg); ov.remove(); if(onSave) onSave(); }
    if(t.getAttribute('data-act')==='chibiCancel'){ ov.remove(); }
  });
}

function _mapOpenRoom(container, mapData, houseId){
  var house = (mapData.houses||[]).find(function(h){ return h.id===houseId; });
  if(!house) return;
  if(!house.rooms) house.rooms = { furniture: _defaultFurniture() };
  var furniture = house.rooms.furniture || [];

  var isMyH = mapData.myHouseId === houseId;
  var npcOwner = null, npcOwnerName = '';
  for(var nk in (mapData.npcHouses||{})){ if(mapData.npcHouses[nk]===houseId){ npcOwner=nk; break; } }
  if(npcOwner){ try{ var db2=loadContactsDB(); var n2=findContactById(db2,npcOwner); if(n2) npcOwnerName=n2.name||''; }catch(e){} }
  var ownerLabel = isMyH ? '我的家' : (npcOwner ? esc(npcOwnerName)+'的家' : house.name);

  // ★ NPC 余额辅助函数 — 存在 mapData.npcBalances[npcId] 里，与家具同条保存路径
  function _roomGetBalance(){
    if(!npcOwner) return loadWallet().balance;
    if(!mapData.npcBalances) mapData.npcBalances = {};
    if(mapData.npcBalances[npcOwner] == null) mapData.npcBalances[npcOwner] = 3000; // NPC初始余额
    return mapData.npcBalances[npcOwner];
  }
  function _roomSpend(amount, desc){
    if(!npcOwner){ walletSpend(amount, desc); return; }
    if(!mapData.npcBalances) mapData.npcBalances = {};
    if(mapData.npcBalances[npcOwner] == null) mapData.npcBalances[npcOwner] = 3000;
    mapData.npcBalances[npcOwner] = Math.max(0, mapData.npcBalances[npcOwner] - amount);
  }
  function _roomCanAfford(amount){
    return _roomGetBalance() >= amount;
  }

  var roomEl = doc.createElement('div');
  roomEl.className = 'mapRoomWrap';
  if(npcOwner) roomEl.setAttribute('data-npc-owner', npcOwner);
  if(npcOwnerName) roomEl.setAttribute('data-npc-name', npcOwnerName);
  roomEl.setAttribute('data-house-id', houseId);

  // 状态
  var _editMode = false;
  var _dragTarget = null;
  var _winTarget = null; // 'left' | 'right' | null — 当前编辑中的窗户
  var _roomZoom = 1, _roomPanX = 0, _roomPanY = 0;
  var _lightTimer = null;

  function _applyTransform(){
    var svg = roomEl.querySelector('.mapRoomSvgInner');
    if(svg) svg.style.transform = 'translate('+_roomPanX+'px,'+_roomPanY+'px) scale('+_roomZoom+')';
    var zl = roomEl.querySelector('[data-el="zoomLabel"]');
    if(zl) zl.textContent = Math.round(_roomZoom*100)+'%';
  }

  function renderRoom(){
    try{
    var lighting = _roomGetLighting();
    var html = '';

    // 头部
    html += '<div class="mapRoomHeader">';
    html += '<div class="mapRoomTitle">'+esc(house.name)+' <span style="font-size:10px;color:rgba(20,24,28,.4);font-weight:400;">'+ownerLabel+'</span></div>';
    html += '<div class="mapRoomToolbar">';
    if(isMyH || npcOwner){
      html += '<button data-act="roomToggleEdit"'+(_editMode?' class="active"':'')+'>'+(_editMode?'✓ 完成':_roomUiIcon('edit')+'<span>装修</span>')+'</button>';
    }
    var _chibOwner = npcOwner || (isMyH ? 'me' : null);
    if(_chibOwner){
      var _chibCfg = (typeof _getChibiSettings==='function') ? _getChibiSettings(_chibOwner) : null;
      html += '<button data-act="roomChibiEdit" style="'+(_chibCfg&&_chibCfg.enabled?'color:var(--ph-icon-inner-tint,var(--ph-text));':'')+'" title="角色设置">'+_roomUiIcon('user')+'</button>';
    }
    html += '<span class="mapRoomWallet">'+_roomUiIcon('money')+'<span>$'+_roomGetBalance()+'</span></span>';
    html += '</div>';
    html += '</div>';

    // SVG容器
    html += '<div class="mapRoomSvgWrap" data-el="svgWrap">';
    html += '<div class="mapRoomTimeLabel">'+lighting.phase+' '+(lighting.hour<10?'0':'')+lighting.hour+':00</div>';
    html += '<svg class="mapRoomSvgInner" viewBox="-20 -60 340 280" xmlns="http://www.w3.org/2000/svg" style="width:96%;max-height:260px;" preserveAspectRatio="xMidYMid meet">';

    // === defs ===
    html += '<defs>';
    html += '<filter id="roomShadow"><feDropShadow dx="2" dy="3" stdDeviation="4" flood-opacity="'+(lighting.shadowAlpha||0.08)+'"/></filter>';
    // 窗户光束（从窗户打到地板的光斑）
    html += '<radialGradient id="windowLight" cx="0.3" cy="0.3" r="0.7"><stop offset="0%" stop-color="'+lighting.windowGlow+'" /><stop offset="100%" stop-color="rgba(255,255,255,0)"/></radialGradient>';
    html += '<radialGradient id="lampLight" cx="0.5" cy="0.5" r="0.5"><stop offset="0%" stop-color="'+lighting.lampGlow+'" /><stop offset="100%" stop-color="rgba(255,255,255,0)"/></radialGradient>';
    html += '</defs>';

    // === 地板 ===
    html += '<polygon points="150,190 290,118 150,46 10,118" fill="#E8DEC8" stroke="rgba(180,168,140,0.2)" stroke-width="0.5" filter="url(#roomShadow)"/>';
    // 格子地板
    var tileW = 28, tileH = 14;
    for(var ty=0;ty<6;ty++){
      for(var tx=0;tx<6;tx++){
        var isAlt = (tx+ty)%2===0;
        var tcx = 150 + (tx-3)*tileW/2 - (ty-3)*tileW/2;
        var tcy = 118 + (tx-3)*tileH/2 + (ty-3)*tileH/2;
        if(isAlt){
          html += '<polygon points="'+(tcx)+','+(tcy-tileH/2)+' '+(tcx+tileW/2)+','+(tcy)+' '+(tcx)+','+(tcy+tileH/2)+' '+(tcx-tileW/2)+','+(tcy)+'" fill="rgba(180,200,140,0.18)"/>';
        }
      }
    }
    // 窗户光斑投射到地板
    html += '<ellipse cx="80" cy="135" rx="40" ry="22" fill="url(#windowLight)" opacity="0.6"/>';
    html += '<line x1="150" y1="46" x2="290" y2="118" stroke="rgba(255,255,255,0.3)" stroke-width="0.5"/>';
    html += '<line x1="150" y1="46" x2="10" y2="118" stroke="rgba(255,255,255,0.2)" stroke-width="0.5"/>';

    // === 左墙 ===
    html += '<polygon points="10,118 150,46 150,-24 10,48" fill="#F2EAD8" stroke="rgba(170,158,130,0.15)" stroke-width="0.5"/>';
    for(var wi=0;wi<6;wi++){
      html += '<line x1="'+(10+(150-10)*wi/6).toFixed(1)+'" y1="'+(48+(118-48)*(1-wi/6)).toFixed(1)+'" x2="'+(10+(150-10)*wi/6).toFixed(1)+'" y2="'+(-24+(48-(-24))*(1-wi/6)).toFixed(1)+'" stroke="rgba(200,190,165,0.12)" stroke-width="0.5"/>';
    }
    html += '<line x1="10" y1="118" x2="150" y2="46" stroke="rgba(160,148,120,0.3)" stroke-width="1.5"/>';
    html += '<line x1="10" y1="114" x2="150" y2="42" stroke="rgba(160,148,120,0.15)" stroke-width="0.5"/>';

    // === 右墙 ===
    html += '<polygon points="150,46 290,118 290,48 150,-24" fill="#E8E0CE" stroke="rgba(170,158,130,0.15)" stroke-width="0.5"/>';
    html += '<line x1="150" y1="46" x2="290" y2="118" stroke="rgba(160,148,120,0.3)" stroke-width="1.5"/>';
    html += '<line x1="150" y1="42" x2="290" y2="114" stroke="rgba(160,148,120,0.15)" stroke-width="0.5"/>';
    html += '<line x1="150" y1="-24" x2="150" y2="46" stroke="rgba(160,148,120,0.2)" stroke-width="0.8"/>';

    // === 窗户（从house数据读取位置/缩放，装修可编辑） ===
    var _winStyle = house._windowStyle || 'default';
    // 窗户位置数据（装修模式可调）
    var wL = house._winLeft || {ox:75, oy:50, sc:1};
    var wR = house._winRight || {ox:225, oy:68, sc:1};
    // 经典格窗 — 左墙坐标，沿左墙方向，宽度与右窗(rwx2-rwx1=60)匹配
    // 左墙: (10,118)→(150,46), 取 t=0.25~0.68 段
    // t=0.25: (10+0.25*140, 118-0.25*72) = (45, 100)
    // t=0.68: (10+0.68*140, 118-0.68*72) = (105, 69)
    var lwx1=45, lwy1=100, lwx2=105, lwy2=69;

    if(_winStyle === 'modern'){
      var _wlSel = _editMode && _winTarget==='left';
      // Left wall window highlight: isometric left-face quad (w=2,d=60,h=40)
      html += '<g transform="translate('+wL.ox+','+wL.oy+') scale('+wL.sc+')" data-win="left" style="cursor:'+(_editMode?'pointer':'default')+';">';
      if(_wlSel) html += '<polygon points="-62,-39 0,-9 0,1 -62,-29" fill="rgba(100,180,80,.18)" stroke="rgba(100,180,80,.6)" stroke-width="0.8" stroke-dasharray="3,2"/>';
      // 窗框 w=2,d=60,h=40 (挂左墙)
      html += '<g transform="translate(0,0)">';
      html += '<rect x="0" y="-40" width="2" height="40" class="wht-r" transform="translate(-60,30) matrix(1,0.5,0,1,0,0)"/>';
      html += '<rect x="0" y="-40" width="60" height="40" class="wht-l" transform="translate(2,1) matrix(-1,0.5,0,1,0,0)"/>';
      html += '<rect x="0" y="0" width="2" height="60" class="wht-t" transform="translate(0,-40) matrix(1,0.5,-1,0.5,0,0)"/>';
      html += '</g>';
      // 玻璃和分隔条（左面matrix）
      html += '<g transform="translate(2,1) matrix(-1,0.5,0,1,0,0)">';
      html += '<rect x="2" y="-38" width="17" height="36" fill="rgba(230,238,245,0.65)" stroke="rgba(210,218,225,0.4)" stroke-width="0.4"/>';
      html += '<rect x="21" y="-38" width="18" height="36" fill="rgba(230,238,245,0.65)" stroke="rgba(210,218,225,0.4)" stroke-width="0.4"/>';
      html += '<rect x="41" y="-38" width="17" height="36" fill="rgba(230,238,245,0.65)" stroke="rgba(210,218,225,0.4)" stroke-width="0.4"/>';
      html += '<rect x="4" y="-34" width="5" height="20" fill="rgba(255,255,255,0.15)"/>';
      html += '<rect x="23" y="-34" width="5" height="20" fill="rgba(255,255,255,0.15)"/>';
      html += '<rect x="19" y="-40" width="2" height="40" fill="#EAEAEA" stroke="#DDD" stroke-width="0.3"/>';
      html += '<rect x="39" y="-40" width="2" height="40" fill="#EAEAEA" stroke="#DDD" stroke-width="0.3"/>';
      html += '</g>';
      html += '</g>';

      // ---- 右墙：镜像版本（用右面matrix） ----
      var _wrSel = _editMode && _winTarget==='right';
      // Right wall window highlight: isometric right-face quad (w=60,d=2,h=40)
      html += '<g transform="translate('+wR.ox+','+wR.oy+') scale('+wR.sc+')" data-win="right" style="cursor:'+(_editMode?'pointer':'default')+';">';
      if(_wrSel) html += '<polygon points="0,-39 62,-9 62,1 0,-29" fill="rgba(100,180,80,.18)" stroke="rgba(100,180,80,.6)" stroke-width="0.8" stroke-dasharray="3,2"/>';
      // 窗框 w=60,d=2,h=40 (挂右墙)
      html += '<g transform="translate(0,0)">';
      html += '<rect x="0" y="-40" width="60" height="40" class="wht-r" transform="translate(-2,1) matrix(1,0.5,0,1,0,0)"/>';
      html += '<rect x="0" y="-40" width="2" height="40" class="wht-l" transform="translate(60,30) matrix(-1,0.5,0,1,0,0)"/>';
      html += '<rect x="0" y="0" width="60" height="2" class="wht-t" transform="translate(0,-40) matrix(1,0.5,-1,0.5,0,0)"/>';
      html += '</g>';
      // 玻璃和分隔条（右面matrix）
      html += '<g transform="translate(-2,1) matrix(1,0.5,0,1,0,0)">';
      html += '<rect x="2" y="-38" width="17" height="36" fill="rgba(220,230,242,0.6)" stroke="rgba(200,210,222,0.35)" stroke-width="0.4"/>';
      html += '<rect x="21" y="-38" width="18" height="36" fill="rgba(220,230,242,0.6)" stroke="rgba(200,210,222,0.35)" stroke-width="0.4"/>';
      html += '<rect x="41" y="-38" width="17" height="36" fill="rgba(220,230,242,0.6)" stroke="rgba(200,210,222,0.35)" stroke-width="0.4"/>';
      html += '<rect x="4" y="-34" width="5" height="20" fill="rgba(255,255,255,0.12)"/>';
      html += '<rect x="19" y="-40" width="2" height="40" fill="#E4E4E4" stroke="#D8D8D8" stroke-width="0.3"/>';
      html += '<rect x="39" y="-40" width="2" height="40" fill="#E4E4E4" stroke="#D8D8D8" stroke-width="0.3"/>';
      html += '</g>';
      html += '</g>';
    } else {
      // 经典格窗 — 左窗用 polygon 坐标直接绘制，与右窗完全对称
      // 右窗：宽60，高32(rwy1-32=10, rwy1=42 → 高=32)，斜率+0.5
      // 左窗：宽60，高32，斜率-0.5（左墙方向）
      // 锚点近端底(45,100)，远端底(105,70)，近端顶(45,68)，远端顶(105,38)
      var lwx1=45, lwy1=100, lwx2=105, lwy2=70;
      var _wlSel2 = _editMode && _winTarget==='left';
      html += '<g transform="translate('+((wL.ox||75)-75)+','+((wL.oy||50)-50)+') scale('+(wL.sc||1)+')" data-win="left" style="cursor:'+(_editMode?'pointer':'default')+';">';
      if(_wlSel2) html += '<polygon points="'+lwx1+','+(lwy1-36)+' '+lwx2+','+(lwy2-36)+' '+lwx2+','+(lwy2+4)+' '+lwx1+','+(lwy1+4)+'" fill="rgba(100,180,80,.18)" stroke="rgba(100,180,80,.6)" stroke-width="0.8" stroke-dasharray="3,2"/>';
      // 主窗面 polygon（近端顶→远端顶→远端底→近端底）
      html += '<polygon points="'+lwx1+','+(lwy1-32)+' '+lwx2+','+(lwy2-32)+' '+lwx2+','+lwy2+' '+lwx1+','+lwy1+'" fill="'+lighting.windowGlow+'" stroke="#A89878" stroke-width="1.2"/>';
      // 竖向中线（x中点，从顶边中点到底边中点）
      html += '<line x1="'+((lwx1+lwx2)/2)+'" y1="'+((lwy1-32+lwy1)/2)+'" x2="'+((lwx1+lwx2)/2)+'" y2="'+((lwy2-32+lwy2)/2)+'" stroke="#A89878" stroke-width="0.8"/>';
      // 横向中线（近端y-16 → 远端y-16）
      html += '<line x1="'+lwx1+'" y1="'+(lwy1-16)+'" x2="'+lwx2+'" y2="'+(lwy2-16)+'" stroke="#A89878" stroke-width="0.8"/>';
      html += '</g>';

      // 经典格窗 - 右墙（不变）
      var rwx1=195, rwy1=42, rwx2=255, rwy2=72;
      var _wrSel2 = _editMode && _winTarget==='right';
      html += '<g transform="translate('+((wR.ox||225)-225)+','+((wR.oy||68)-68)+') scale('+(wR.sc||1)+')" data-win="right" style="cursor:'+(_editMode?'pointer':'default')+';">';
      if(_wrSel2) html += '<polygon points="'+rwx1+','+(rwy1-36)+' '+rwx2+','+(rwy2-36)+' '+rwx2+','+(rwy2+4)+' '+rwx1+','+(rwy1+4)+'" fill="rgba(100,180,80,.18)" stroke="rgba(100,180,80,.6)" stroke-width="0.8" stroke-dasharray="3,2"/>';
      html += '<polygon points="'+rwx1+','+(rwy1-32)+' '+rwx2+','+(rwy2-32)+' '+rwx2+','+rwy2+' '+rwx1+','+rwy1+'" fill="'+lighting.windowGlow+'" stroke="#A89878" stroke-width="1.2"/>';
      html += '<line x1="'+((rwx1+rwx2)/2)+'" y1="'+((rwy1-32+rwy1)/2)+'" x2="'+((rwx1+rwx2)/2)+'" y2="'+((rwy2-32+rwy2)/2)+'" stroke="#A89878" stroke-width="0.8"/>';
      html += '<line x1="'+rwx1+'" y1="'+(rwy1-16)+'" x2="'+rwx2+'" y2="'+(rwy2-16)+'" stroke="#A89878" stroke-width="0.8"/>';
      html += '</g>';
    }

    // 装修模式：显示窗户编辑提示
    if(_editMode){
      html += '<text x="75" y="15" text-anchor="middle" font-size="6" fill="rgba(100,160,80,0.6)">左窗</text>';
      html += '<text x="225" y="32" text-anchor="middle" font-size="6" fill="rgba(100,160,80,0.6)">右窗</text>';
    }

    // === 门（贴地！右墙从150,46到290,118） ===
    // 门底边在墙底线上：x=258时 y=46+(258-150)/(290-150)*(118-46)=101.5, x=284时 y=112.5
    html += '<polygon points="258,101 284,114 284,56 258,44" fill="#A08A6A" stroke="#8A7454" stroke-width="0.8"/>';
    html += '<polygon points="260,100 282,112 282,58 260,46" fill="#B89A7A" stroke="none"/>';
    html += '<circle cx="264" cy="82" r="1.5" fill="#D0B888" stroke="#A08A6A" stroke-width="0.4"/>';

    // === 墙上装饰已移除 ===

    // === 墙壁环境光（家具之前，不遮盖家具） ===
    if(lighting.ambientTint && lighting.ambientTint !== 'rgba(0,0,0,0)'){
      html += '<polygon points="10,118 150,46 150,-24 10,48" fill="'+lighting.ambientTint+'" style="pointer-events:none;"/>';
      html += '<polygon points="150,46 290,118 290,48 150,-24" fill="'+lighting.ambientTint+'" style="pointer-events:none;"/>';
    }

    // === 家具渲染 ===
    var furnItems = [];
    furniture.forEach(function(f){
      if(!f.owned) return;
      var cat = FURNITURE_CATALOG[f.type];
      if(!cat) return;
      var fx, fy;
      if(typeof f.roomX === 'number' && typeof f.roomY === 'number'){
        fx = f.roomX; fy = f.roomY;
      } else {
        var pos = _defaultFurnPositions[f.type] || { gx:0, gy:0 };
        var gx = (typeof f.gx === 'number') ? f.gx : pos.gx;
        var gy = (typeof f.gy === 'number') ? f.gy : pos.gy;
        var iso = _isoProject(gx, gy);
        fx = iso.x; fy = iso.y;
      }
      furnItems.push({ f:f, type:f.type, x:fx, y:fy, sortY: fy + fx*0.1, zIdx: f.furnZIndex||0 });
    });
    furnItems.sort(function(a,b){ if(a.zIdx!==b.zIdx) return a.zIdx-b.zIdx; return a.sortY - b.sortY; });

    furnItems.forEach(function(item){
      var isSelected = _editMode && _dragTarget === item.f.id;
      var cat4 = FURNITURE_CATALOG[item.type] || {};
      var _stObj = null;
      if(cat4.styles && cat4.styles.length && item.f.styleId){
        _stObj = cat4.styles.find(function(ss){ return ss.id === item.f.styleId; });
      }
      var _usePng = (_stObj && _stObj.png && _stObj.png.length > 10) ? _stObj.png : cat4.png;
      var _usePngW = _stObj ? (_stObj.pngW || cat4.pngW) : cat4.pngW;
      var _usePngH = _stObj ? (_stObj.pngH || cat4.pngH) : cat4.pngH;
      var hasPng = _usePng && _usePng.length > 10;
      var drawFn = _roomFurnSVG[item.type];
      var sc = item.f.furnScale || 0.6;
      var flip = item.f.flipped ? -1 : 1;

      html += '<g class="rm-furn-wrap'+(isSelected?' dragging':'')+'" data-furnid="'+item.f.id+'" data-furntype="'+item.type+'">';
      if(isSelected){
        var sr = 16*sc;
        html += '<polygon points="'+(item.x)+','+(item.y-sr)+' '+(item.x+sr)+','+(item.y-sr/2)+' '+(item.x)+','+(item.y)+' '+(item.x-sr)+','+(item.y-sr/2)+'" fill="rgba(100,180,80,0.15)" stroke="rgba(100,180,80,0.5)" stroke-width="0.8" stroke-dasharray="3,2"/>';
      }

      if(hasPng){
        var pw = (_usePngW||40)*sc, ph = (_usePngH||40)*sc;
        html += '<g transform="translate('+item.x+','+item.y+') scale('+(flip)+',1) translate(-'+item.x+',-'+item.y+')">';
        html += '<image href="'+_usePng+'" x="'+(item.x - pw/2)+'" y="'+(item.y - ph)+'" width="'+pw+'" height="'+ph+'" style="cursor:pointer;" class="rm-furn"/>';
        html += '</g>';
      } else if(drawFn){
        // Scale + optional flip: translate to origin, scale, translate back
        html += '<g transform="translate('+item.x+','+item.y+') scale('+(flip*sc)+','+sc+') translate(-'+item.x+',-'+item.y+')">';
        html += drawFn(item.x, item.y, true);
        html += '</g>';
      } else {
        html += '<text x="'+item.x+'" y="'+item.y+'" text-anchor="middle" font-size="'+(20*sc)+'" style="cursor:pointer;" class="rm-furn">'+cat4.emoji+'</text>';
      }

      if(_editMode){
        html += '<text x="'+item.x+'" y="'+(item.y+12*sc+6)+'" text-anchor="middle" font-size="6" fill="rgba(100,160,80,0.8)" font-weight="600">'+cat4.label+(item.f.flipped?' ↔':'')+'</text>';
      }
      html += '</g>';
    });

    // === 常驻装饰（已移除） ===

    // ★ Chibi 角色（我的家 or NPC家都支持）
    var _chibOwnerKey = npcOwner || (isMyH ? 'me' : null);
    if(_chibOwnerKey){
      try{
        var _chibiFn = (typeof _getChibiSettings==='function') ? _getChibiSettings(_chibOwnerKey) : null;
        if(_chibiFn && _chibiFn.enabled){
          var _chibScene = _getChibiScene(_chibOwnerKey);
          var _chibScale = _chibiFn.scale || 0.42;
          var _chibSvg = _chibiFurnSVG({ gender:_chibiFn.gender, hairStyle:_chibiFn.hairStyle, hairColor:_chibiFn.hairColor, skinColor:_chibiFn.skinColor, coatColor:_chibiFn.coatColor, catEars:_chibiFn.catEars, acc:_chibiFn.acc, outfit:_chibiFn.outfit, scene:_chibScene, scale:_chibScale });

          var _cx = typeof _chibiFn.posX === 'number' ? _chibiFn.posX : 150;
          var _cy = typeof _chibiFn.posY === 'number' ? _chibiFn.posY : 100;
          try{
            var _snapType = _chibScene==='sleep' ? 'bed' : _chibScene==='eat' ? 'stove' : _chibScene==='sit' ? 'sofa' : null;
            if(_snapType){
              var _snapFurn = furniture.find(function(f){ return f.type===_snapType && f.owned; });
              if(_snapFurn){
                var _sp;
                if(typeof _snapFurn.roomX==='number'){ _sp={x:_snapFurn.roomX, y:_snapFurn.roomY}; }
                else { var _spos=_defaultFurnPositions[_snapType]||{gx:0,gy:0}; _sp=_isoProject(typeof _snapFurn.gx==='number'?_snapFurn.gx:_spos.gx, typeof _snapFurn.gy==='number'?_snapFurn.gy:_spos.gy); }
                _cx = _sp.x;
                _cy = _sp.y - (_chibScene==='sleep'?8:(_chibScene==='sit'?10:15));
              }
            }
          }catch(e){}

          html += '<g data-el="chibiSprite" style="cursor:pointer;" transform="translate('+_cx+','+_cy+')">';
          html += _chibSvg;
          html += '</g>';
        }
      }catch(e){}
    }

    // === 夜间光照：蒙版法（有灯的地方挖洞，再叠淡暖光） ===
    var _lampPositions = [];
    if(lighting.lampSpread > 0){
      furniture.forEach(function(lf){
        if(!lf.owned) return;
        if(lf.type !== 'lamp' && lf.type !== 'lamp2') return;
        var lfx, lfy;
        if(typeof lf.roomX === 'number'){ lfx=lf.roomX; lfy=lf.roomY; }
        else {
          var lpos = _defaultFurnPositions[lf.type] || {gx:1,gy:0};
          var lip = _isoProject(typeof lf.gx==='number'?lf.gx:lpos.gx, typeof lf.gy==='number'?lf.gy:lpos.gy);
          lfx = lip.x; lfy = lip.y;
        }
        _lampPositions.push({x:lfx, y:lfy, sc:lf.furnScale||0.6});
      });
    }

    if(lighting.lampSpread > 0 && _lampPositions.length > 0){
      // 定义蒙版：白色=显示遮罩，黑色=透明（灯光穿透）
      var maskId = 'nightMask_' + Date.now();
      html += '<defs>';
      // 径向渐变：灯光区域从黑(透明)到白(遮罩)
      _lampPositions.forEach(function(lp, li){
        html += '<radialGradient id="lg'+li+'_'+maskId+'" cx="50%" cy="50%" r="50%">';
        html += '<stop offset="0%" stop-color="black"/>';
        html += '<stop offset="40%" stop-color="rgba(0,0,0,0.7)"/>';
        html += '<stop offset="100%" stop-color="white"/>';
        html += '</radialGradient>';
      });
      html += '<mask id="'+maskId+'">';
      html += '<rect x="-20" y="-60" width="340" height="280" fill="white"/>';
      _lampPositions.forEach(function(lp, li){
        var r = 55 * lp.sc;
        html += '<ellipse cx="'+lp.x+'" cy="'+(lp.y-5)+'" rx="'+r+'" ry="'+(r*0.6)+'" fill="url(#lg'+li+'_'+maskId+')"/>';
      });
      html += '</mask>';
      html += '</defs>';

      // 夜间遮罩（有灯的地方被mask挖洞）
      html += '<polygon points="-20,-60 320,-60 320,220 -20,220" fill="'+lighting.overlay+'" mask="url(#'+maskId+')" style="pointer-events:none;"/>';

      // 灯光区域叠加淡暖光
      _lampPositions.forEach(function(lp){
        var gs = lighting.lampSpread;
        var lsc = lp.sc;
        // 柔和大范围暖光
        html += '<ellipse cx="'+lp.x+'" cy="'+(lp.y+2)+'" rx="'+(50*lsc)+'" ry="'+(30*lsc)+'" fill="rgba(255,230,170,'+(gs*0.12).toFixed(3)+')" style="pointer-events:none;"/>';
        // 中心暖光
        html += '<ellipse cx="'+lp.x+'" cy="'+(lp.y-10*lsc)+'" rx="'+(25*lsc)+'" ry="'+(15*lsc)+'" fill="rgba(255,240,190,'+(gs*0.15).toFixed(3)+')" style="pointer-events:none;"/>';
        // 灯泡光点
        html += '<ellipse cx="'+lp.x+'" cy="'+(lp.y-22*lsc)+'" rx="'+(6*lsc)+'" ry="'+(4*lsc)+'" fill="rgba(255,250,220,'+(gs*0.25).toFixed(3)+')" style="pointer-events:none;"/>';
      });
    } else {
      // 无灯/白天：普通遮罩
      html += '<polygon points="-20,-60 320,-60 320,220 -20,220" fill="'+lighting.overlay+'" style="pointer-events:none;"/>';
    }

    html += '</svg>';
    // Controls: always show zoom + pan. In edit mode add selected-target controls only.
    html += '<div class="mapRoomZoomBar">';
    html += '<button data-act="roomZoomIn">+</button>';
    html += '<button data-act="roomZoomOut">−</button>';
    html += '<button data-act="roomZoomReset" style="font-size:10px;">↺</button>';
    html += '<div style="height:2px;"></div>';
    html += '<button data-act="roomPanUp" style="font-size:10px;">▲</button>';
    html += '<div class="zDirRow"><button data-act="roomPanLeft">◀</button><button data-act="roomPanRight">▶</button></div>';
    html += '<button data-act="roomPanDown" style="font-size:10px;">▼</button>';
    if(_editMode && (_dragTarget || _winTarget)){
      html += '<div style="height:2px;border-top:1px solid rgba(0,0,0,0.08);margin:2px 0;width:20px;"></div>';
      html += '<button data-act="roomScaleUp" style="font-size:9px;" title="放大">+</button>';
      html += '<button data-act="roomScaleDown" style="font-size:9px;" title="缩小">−</button>';
      if(_dragTarget){
        html += '<button data-act="roomFlip" style="font-size:9px;" title="翻转">↔</button>';
        html += '<button data-act="roomZUp" style="font-size:8px;" title="前面">前</button>';
        html += '<button data-act="roomZDown" style="font-size:8px;" title="后面">后</button>';
      }
    }
    html += '</div>';
    if(_editMode && (_dragTarget || _winTarget)){
      var selF = _dragTarget ? furniture.find(function(ff){return ff.id===_dragTarget;}) : null;
      var selCat = selF ? (FURNITURE_CATALOG[selF.type]||{}) : {};
      var curScale = selF ? (selF.furnScale||0.6) : 0.6;
      if(_winTarget){
        html += '<div class="mapRoomEditHint">'+(_winTarget==='left'?'左窗':'右窗')+'已选 — ▲▼◀▶移动 窗+/−缩放 · 点击另一窗切换</div>';
      } else {
        html += '<div class="mapRoomEditHint">'+esc(selCat.label||'家具')+' ('+Math.round(curScale*100)+'%'+(selF&&selF.flipped?' 已翻转':'')+') — ▲▼◀▶移动 🔍缩放 ↔翻转</div>';
      }
    } else if(_editMode){
      html += '<div class="mapRoomEditHint">点击家具或窗户进行编辑 · 点击空白取消选择</div>';
    }
    html += '</div>';

    // 家具网格
    html += '<div class="mapRoomGrid">';
    furniture.forEach(function(f){
      var cat = FURNITURE_CATALOG[f.type];
      if(!cat) return;
      var fxDesc = [];
      for(var fk in (cat.fx||{})){ var v=cat.fx[fk]; var names={mood:'心情',energy:'精力',health:'健康',hunger:'饱腹',fun:'娱乐'}; if(v>0)fxDesc.push((names[fk]||fk)+'+'+v); }
      if(f.owned){
        var _curSL = '';
        if(cat.styles && cat.styles.length > 1 && f.styleId){
          var _csO = cat.styles.find(function(ss){return ss.id===f.styleId;});
          if(_csO) _curSL = ' · '+_csO.label;
        }
        html += '<div class="mapFurnSlot" style="position:relative;" data-furnid="'+f.id+'" data-furntype="'+f.type+'">';
        html += '<span class="fe" data-act="'+(_editMode?'roomMove':'roomUse')+'" data-furnid="'+f.id+'" data-furntype="'+f.type+'">'+_roomUiIcon(f.type||cat.emoji)+'</span>';
        html += '<span class="fn" data-act="'+(_editMode?'roomMove':'roomUse')+'" data-furnid="'+f.id+'" data-furntype="'+f.type+'">'+cat.label+_curSL+(_editMode?' · 可拖动':'')+'</span>';
        html += '<span class="fd" data-act="'+(_editMode?'roomMove':'roomUse')+'" data-furnid="'+f.id+'" data-furntype="'+f.type+'">'+(_editMode?'点击后拖到新位置':fxDesc.join(' '))+'</span>';
        if(cat.styles && cat.styles.length > 1 && !_editMode){
          html += '<span data-act="changeStyle" data-furnid="'+f.id+'" data-furntype="'+f.type+'" style="position:absolute;right:3px;top:3px;font-size:9px;background:rgba(0,0,0,.06);border-radius:8px;padding:1px 6px;cursor:pointer;z-index:2;">🎨换款</span>';
        }
        html += '</div>';
      } else {
        html += '<div class="mapFurnSlot locked" data-act="roomBuy" data-furntype="'+f.type+'" data-furnid="'+f.id+'">';
        html += '<span class="fe">'+_roomUiIcon(f.type||cat.emoji)+'</span>';
        html += '<span class="fn">'+cat.label+' · 已锁</span>';
        html += '<span class="fd">$'+cat.cost+'</span>';
        html += '</div>';
      }
    });
    if(isMyH){
      html += '<div class="mapFurnSlot" data-act="roomShop" style="border-style:dashed;opacity:0.6;"><span class="fe">'+_roomUiIcon('plus')+'</span><span class="fn">购买家具</span></div>';
    }
    html += '</div>';

    // 日志 — 只在自己的房间底部显示，NPC房间靠点击家具发现（有惊喜感）
    if(isMyH){
      var logData = _mapLoadLog();
      var houseLogs = _safeArr(logData.logs).filter(function(l){ return l.npcId==='me' || l.landmarkId===houseId; }).slice(-3).reverse();
      if(houseLogs.length){
        html += '<div class="mapRoomLog"><div style="font-size:10px;color:rgba(20,24,28,.35);margin-bottom:3px;">最近动态</div>';
        houseLogs.forEach(function(l){
          html += '<div style="font-size:10px;color:rgba(20,24,28,.45);padding:1px 0;">'+esc(l.npcName||'???')+' · '+esc(l.action||'')+'</div>';
        });
        html += '</div>';
      }
    }

    roomEl.innerHTML = html;
    _applyTransform();
    _initRoomGestures();
    }catch(err){
      console.error('[Room] renderRoom error:', err);
      roomEl.innerHTML = '<div style="padding:20px;text-align:center;color:rgba(20,24,28,.5);font-size:13px;">房间加载失败，请重试<br><small style="font-size:10px;opacity:.5;">'+String(err&&err.message||err)+'</small><br><button onclick="this.closest(\'.mapRoomWrap\').remove()" style="margin-top:12px;padding:8px 16px;border-radius:10px;border:0;background:rgba(0,0,0,.06);cursor:pointer;font-size:12px;">返回</button></div>';
    }
  }

  // === 缩放拖拽手势 ===
  function _initRoomGestures(){
    var wrap = roomEl.querySelector('[data-el="svgWrap"]');
    if(!wrap) return;
    var isPanning = false, lastX=0, lastY=0, lastDist=0;

    wrap.addEventListener('wheel', function(e){
      e.preventDefault();
      var delta = e.deltaY > 0 ? -0.1 : 0.1;
      _roomZoom = Math.max(0.5, Math.min(4, _roomZoom + delta));
      _applyTransform();
    }, {passive:false});

    wrap.addEventListener('touchstart', function(e){
      if(e.touches.length===1){
        isPanning = true;
        lastX = e.touches[0].clientX;
        lastY = e.touches[0].clientY;
      } else if(e.touches.length===2){
        isPanning = false;
        lastDist = Math.hypot(e.touches[0].clientX-e.touches[1].clientX, e.touches[0].clientY-e.touches[1].clientY);
      }
    }, {passive:true});

    wrap.addEventListener('touchmove', function(e){
      if(e.touches.length===1 && isPanning && !_editMode){
        var dx = e.touches[0].clientX - lastX, dy = e.touches[0].clientY - lastY;
        _roomPanX += dx; _roomPanY += dy;
        _roomPanX = Math.max(-150,Math.min(150,_roomPanX));
        _roomPanY = Math.max(-150,Math.min(150,_roomPanY));
        lastX = e.touches[0].clientX; lastY = e.touches[0].clientY;
        _applyTransform();
      } else if(e.touches.length===2){
        var dist = Math.hypot(e.touches[0].clientX-e.touches[1].clientX, e.touches[0].clientY-e.touches[1].clientY);
        if(lastDist>0){
          var scale = dist/lastDist;
          _roomZoom = Math.max(0.5, Math.min(4, _roomZoom * scale));
          _applyTransform();
        }
        lastDist = dist;
      }
    }, {passive:true});

    wrap.addEventListener('touchend', function(){ isPanning=false; lastDist=0; }, {passive:true});

    // 鼠标拖拽
    wrap.addEventListener('mousedown', function(e){
      if(_editMode) return;
      isPanning = true;
      lastX = e.clientX; lastY = e.clientY;
      wrap.style.cursor = 'grabbing';
    });
    wrap.addEventListener('mousemove', function(e){
      if(!isPanning || _editMode) return;
      _roomPanX += e.clientX - lastX; _roomPanY += e.clientY - lastY;
      _roomPanX = Math.max(-150,Math.min(150,_roomPanX));
      _roomPanY = Math.max(-150,Math.min(150,_roomPanY));
      lastX = e.clientX; lastY = e.clientY;
      _applyTransform();
    });
    wrap.addEventListener('mouseup', function(){ isPanning=false; wrap.style.cursor=''; });
    wrap.addEventListener('mouseleave', function(){ isPanning=false; wrap.style.cursor=''; });

    // SVG点击：普通模式触发家具使用/发现，编辑模式选中拖拽
    if(_editMode){
      wrap.addEventListener('click', function(ev){
        var winG = ev.target.closest('[data-win]');
        if(winG){
          var wSide = winG.getAttribute('data-win');
          _winTarget = (_winTarget === wSide) ? null : wSide;
          _dragTarget = null;
          try{ toast('🪟 '+((_winTarget==='left')?'左窗':'右窗')+'已选中，用 ▲▼◀▶ 移动'); }catch(e){}
          renderRoom(); return;
        }
        var furnG2 = ev.target.closest('.rm-furn-wrap');
        if(furnG2){
          var fid2 = furnG2.getAttribute('data-furnid');
          if(fid2){ _dragTarget=fid2; _winTarget=null; try{toast('🔧 用 ▲▼◀▶ 移动家具');}catch(e){} renderRoom(); }
          return;
        }
        if(ev.target.tagName==='polygon'||ev.target.tagName==='rect'||ev.target===wrap){
          if(_dragTarget||_winTarget){ _dragTarget=null; _winTarget=null; renderRoom(); }
        }
      });
    } else {
      wrap.addEventListener('click', function(ev){
        var furnG = ev.target.closest('.rm-furn-wrap');
        if(furnG){
          var fid = furnG.getAttribute('data-furnid');
          var ftype = furnG.getAttribute('data-furntype');
          if(fid && ftype){
            var fObj = furniture.find(function(ff){ return ff.id===fid; });
            var catObj = FURNITURE_CATALOG[ftype];
            if(fObj && catObj && fObj.owned){
              if(npcOwner){
                _showNpcFurnPanel(container, mapData, houseId, npcOwner, npcOwnerName, fObj, catObj);
              } else {
                try{ var us3=_loadUserState(); for(var k in (catObj.fx||{})){ if(us3.attrs[k]!=null) us3.attrs[k]=_clampUserAttr(k,us3.attrs[k]+(catObj.fx[k]||0)); } us3.lastCalcAt=Date.now(); _saveUserState(us3); }catch(e){}
                try{ toast(catObj.emoji+' '+catObj.desc); }catch(e){}
                renderRoom();
              }
            }
          }
        }
      });
    }
  }
  _lightTimer = setInterval(function(){
    if(!roomEl.parentNode){ clearInterval(_lightTimer); return; }
    // 轻量更新光照overlay
    var lighting2 = _roomGetLighting();
    var tl = roomEl.querySelector('.mapRoomTimeLabel');
    if(tl) tl.textContent = lighting2.phase+' '+(lighting2.hour<10?'0':'')+lighting2.hour+':00';
  }, 300000);

  renderRoom();

  // 事件处理
  roomEl.addEventListener('click', function(ev){
    var tgt = ev.target.closest('[data-act]');
    if(!tgt) return;
    var act = tgt.getAttribute('data-act');

    if(act==='roomBack'){
      clearInterval(_lightTimer);
      if(_mapZoomBar) _mapZoomBar.style.display = '';
      roomEl.remove();
      return;
    }

    if(act==='roomZoomIn'){ _roomZoom=Math.min(4,_roomZoom+0.25); _applyTransform(); return; }
    if(act==='roomZoomOut'){ _roomZoom=Math.max(0.5,_roomZoom-0.25); _applyTransform(); return; }
    if(act==='roomZoomReset'){ _roomZoom=1;_roomPanX=0;_roomPanY=0; _applyTransform(); return; }

    // Direction buttons: move furniture if selected, otherwise pan view
    var panStep = 30, furnStep = 6;
    // Flip furniture
    if(act==='roomFlip'){
      if(_editMode && _dragTarget){
        var ff2 = furniture.find(function(ff){ return ff.id===_dragTarget; });
        if(ff2){ ff2.flipped = !ff2.flipped; house.rooms.furniture = furniture; _mapSave(mapData); renderRoom(); }
      }
      return;
    }

    if(act==='roomZUp'||act==='roomZDown'){
      if(_editMode && _dragTarget){
        var zf = furniture.find(function(ff){ return ff.id===_dragTarget; });
        if(zf){ zf.furnZIndex = (zf.furnZIndex||0) + (act==='roomZUp'?1:-1); house.rooms.furniture = furniture; _mapSave(mapData); renderRoom(); }
      }
      return;
    }

    // Legacy: remove old individual win move actions (now handled via roomPan + _winTarget)

    // Scale furniture
    if(act==='roomScaleUp'||act==='roomScaleDown'){
      var scaleDir = act==='roomScaleUp' ? 1 : -1;
      // window selected → scale window
      if(_editMode && _winTarget){
        if(!house._winLeft) house._winLeft = {ox:75,oy:50,sc:1};
        if(!house._winRight) house._winRight = {ox:225,oy:68,sc:1};
        var wsD2 = scaleDir * 0.1;
        if(_winTarget==='left') house._winLeft.sc = Math.max(0.3, Math.min(2.5, (house._winLeft.sc||1)+wsD2));
        else house._winRight.sc = Math.max(0.3, Math.min(2.5, (house._winRight.sc||1)+wsD2));
        _mapSave(mapData); renderRoom(); return;
      }
      // furniture selected → scale furniture
      if(_editMode && _dragTarget){
        var sf2 = furniture.find(function(ff){ return ff.id===_dragTarget; });
        if(sf2){
          var cur = sf2.furnScale || 0.6;
          sf2.furnScale = scaleDir > 0 ? Math.min(1.5, cur+0.05) : Math.max(0.2, cur-0.05);
          house.rooms.furniture = furniture;
          _mapSave(mapData);
          renderRoom();
        }
      }
      return;
    }

    if(act==='roomPanUp'||act==='roomPanDown'||act==='roomPanLeft'||act==='roomPanRight'){
      // ★ 如果选中了窗户，方向键移动窗户
      if(_editMode && _winTarget){
        if(!house._winLeft) house._winLeft = {ox:75,oy:50,sc:1};
        if(!house._winRight) house._winRight = {ox:225,oy:68,sc:1};
        var winStep = 5;
        var wdx = act==='roomPanLeft' ? -winStep : act==='roomPanRight' ? winStep : 0;
        var wdy = act==='roomPanUp' ? -winStep : act==='roomPanDown' ? winStep : 0;
        if(_winTarget==='left'){ house._winLeft.ox += wdx; house._winLeft.oy += wdy; }
        else { house._winRight.ox += wdx; house._winRight.oy += wdy; }
        _mapSave(mapData); renderRoom();
        return;
      }
      if(_editMode && _dragTarget){
        var mf = furniture.find(function(ff){ return ff.id===_dragTarget; });
        if(mf){
          // Ensure roomX/roomY are initialized
          if(typeof mf.roomX !== 'number'){
            var dp = _defaultFurnPositions[mf.type] || {gx:2,gy:1};
            var ip = _isoProject(typeof mf.gx==='number'?mf.gx:dp.gx, typeof mf.gy==='number'?mf.gy:dp.gy);
            mf.roomX = ip.x; mf.roomY = ip.y;
          }
          if(act==='roomPanUp') mf.roomY -= furnStep;
          if(act==='roomPanDown') mf.roomY += furnStep;
          if(act==='roomPanLeft') mf.roomX -= furnStep;
          if(act==='roomPanRight') mf.roomX += furnStep;
          // Clamp to room area: walls at x≈10-290, y≈50-188
          mf.roomX = Math.max(5, Math.min(285, mf.roomX));
          mf.roomY = Math.max(48, Math.min(188, mf.roomY));
          house.rooms.furniture = furniture;
          _mapSave(mapData);
          renderRoom();
        }
      } else {
        if(act==='roomPanUp') _roomPanY += panStep;
        if(act==='roomPanDown') _roomPanY -= panStep;
        if(act==='roomPanLeft') _roomPanX += panStep;
        if(act==='roomPanRight') _roomPanX -= panStep;
        _roomPanX = Math.max(-200,Math.min(200,_roomPanX));
        _roomPanY = Math.max(-200,Math.min(200,_roomPanY));
        _applyTransform();
      }
      return;
    }

    if(act==='roomSettings'){
      _openRoomSettings(container, mapData, houseId, npcOwner, npcOwnerName);
      return;
    }

    if(act==='roomToggleEdit'){
      _editMode = !_editMode;
      _dragTarget = null;
      _winTarget = null;
      renderRoom();
      return;
    }

    if(act==='roomChibiEdit'){
      var _chibEditOwner = npcOwner || (isMyH ? 'me' : null);
      if(_chibEditOwner){
        _openChibiEditor(container, _chibEditOwner, npcOwner ? npcOwnerName : '我', function(){ renderRoom(); });
      }
      return;
    }

    if(act==='roomMove'){
      var fid0 = tgt.getAttribute('data-furnid');
      _dragTarget = fid0;
      try{ toast('🔧 用 ▲▼◀▶ 方向键移动家具'); }catch(e){}
      renderRoom();
      return;
    }

    if(act==='roomUse'){
      var fid = tgt.getAttribute('data-furnid');
      var f = furniture.find(function(ff){ return ff.id===fid; });
      if(!f) return;
      var cat = FURNITURE_CATALOG[f.type];
      if(!cat) return;

      if(npcOwner){
        // ★ NPC 房间：点击家具 → 显示角色互动面板（日志 + 隐藏秘密）
        _showNpcFurnPanel(container, mapData, houseId, npcOwner, npcOwnerName, f, cat);
      } else {
        // 自己的房间：直接使用
        try{
          var us2 = _loadUserState();
          for(var fk3 in (cat.fx||{})){
            var ak3 = fk3; if(us2.attrs[ak3]!=null) us2.attrs[ak3] = _clampUserAttr(ak3, us2.attrs[ak3]+(cat.fx[fk3]||0));
          }
          us2.lastCalcAt = Date.now(); _saveUserState(us2);
        }catch(e){}
        try{
          var logData2 = _mapLoadLog();
          logData2.logs.push({ id:'log_room_'+Date.now(), npcId:'me', npcName:'我',
            landmarkId:houseId, time:Date.now(), period:'room',
            action:'在家里'+cat.desc, cost:0, statusEffect:cat.fx, isAuto:false });
          if(logData2.logs.length>200) logData2.logs=logData2.logs.slice(-200);
          _mapSaveLog(logData2);
        }catch(e){}
        try{ toast(cat.emoji+' '+cat.desc); }catch(e){}
        renderRoom();
      }
      return;
    }

    if(act==='roomBuy'){
      var ftype = tgt.getAttribute('data-furntype');
      var fid2 = tgt.getAttribute('data-furnid');
      var cat2 = FURNITURE_CATALOG[ftype];
      if(!cat2 || !cat2.cost) return;
      if(!_roomCanAfford(cat2.cost)){ try{ toast('💰 '+(npcOwner?esc(npcOwnerName)+'余额不足':'余额不足')+'！需要 $'+cat2.cost); }catch(e){} return; }
      _roomSpend(cat2.cost, '购买家具：'+cat2.label);
      var f2 = furniture.find(function(ff){ return ff.id===fid2; });
      if(f2){ f2.owned = true; f2.boughtAt = Date.now(); }
      _mapSave(mapData);
      try{ toast('🎉 已购买 '+cat2.emoji+' '+cat2.label); }catch(e){}
      renderRoom();
      return;
    }

    // === 切换款式 ===
    if(act==='changeStyle'){
      var csFid = tgt.getAttribute('data-furnid');
      var csFtype = tgt.getAttribute('data-furntype');
      var csF = furniture.find(function(ff){ return ff.id===csFid; });
      if(!csF) return;
      var csCat = FURNITURE_CATALOG[csFtype];
      if(!csCat || !csCat.styles || csCat.styles.length < 2) return;
      var csH = '<div style="font-size:14px;font-weight:600;margin-bottom:8px;">🎨 切换款式 — '+csCat.label+'</div>';
      csCat.styles.forEach(function(st){
        var isCur = (csF.styleId === st.id) || (!csF.styleId && st.id==='default');
        csH += '<div class="mapActRow" data-act="styleSwitch" data-furnid="'+csFid+'" data-styleid="'+st.id+'" style="min-height:44px;'+(isCur?'border:1px solid rgba(255,255,255,.48);background:rgba(255,255,255, calc(var(--ph-frost-panel-a, .45) + .03));':'')+'">';
        if(st.png && st.png.length > 10){
          csH += '<img src="'+st.png+'" style="width:36px;height:36px;object-fit:contain;margin-right:8px;border-radius:4px;background:rgba(0,0,0,.03);"/>';
        } else {
          csH += '<span style="margin-right:8px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));">'+_roomUiIcon(csF.type||csCat.emoji)+'</span>';
        }
        csH += '<div style="flex:1;"><div style="font-size:13px;font-weight:500;">'+st.label+'</div></div>';
        if(isCur) csH += '<span style="font-size:10px;color:rgba(100,180,80,.8);font-weight:600;">当前</span>';
        csH += '</div>';
      });
      csH += '<button data-act="csClose" style="width:100%;padding:10px;border-radius:10px;border:1px solid rgba(0,0,0,.08);background:#fff;font-size:13px;cursor:pointer;margin-top:8px;">关闭</button>';
      var csOv = _cpShowOverlay(csH);
      csOv.addEventListener('click', function(ev4){
        var t4 = ev4.target.closest('[data-act]');
        if(!t4) return;
        if(t4.getAttribute('data-act')==='csClose'){ csOv.remove(); return; }
        if(t4.getAttribute('data-act')==='styleSwitch'){
          var ff4 = furniture.find(function(fff){return fff.id===t4.getAttribute('data-furnid');});
          if(ff4) ff4.styleId = t4.getAttribute('data-styleid');
          house.rooms.furniture = furniture;
          _mapSave(mapData);
          csOv.remove();
          try{ toast('🎨 已切换款式'); }catch(e){}
          renderRoom();
        }
      });
      return;
    }

    if(act==='roomShop'){
      var shopH = '<div style="font-size:14px;font-weight:600;margin-bottom:8px;display:flex;align-items:center;gap:6px;">'+_roomUiIcon('sofa')+'<span>家具商店</span></div>';
      shopH += '<div style="font-size:11px;color:rgba(20,24,28,.4);margin-bottom:10px;display:flex;align-items:center;gap:6px;">'+_roomUiIcon('money')+'<span>余额: $'+_roomGetBalance()+'</span></div>';

      // ====== 窗户装修 ======
      var curWinStyle = house._windowStyle || 'default';
      shopH += '<div style="font-size:11px;font-weight:600;color:rgba(20,24,28,.5);margin:4px 0 4px;display:flex;align-items:center;gap:6px;">'+_roomUiIcon('window')+'<span>窗户款式（硬装）</span></div>';
      shopH += '<div class="mapActRow" data-act="winStyle" data-winstyle="default" style="min-height:36px;'+(curWinStyle==='default'?'border:1px solid rgba(255,255,255,.48);background:rgba(255,255,255, calc(var(--ph-frost-panel-a, .45) + .03));':'')+'">';
      shopH += '<span style="margin-right:8px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));">'+_roomUiIcon('window')+'</span>';
      shopH += '<div style="flex:1;"><div style="font-size:12px;font-weight:500;">经典格窗</div></div>';
      shopH += (curWinStyle==='default'?'<span style="font-size:10px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));font-weight:600;opacity:.8;">当前</span>':'<span class="mapActCost">免费</span>');
      shopH += '</div>';
      shopH += '<div class="mapActRow" data-act="winStyle" data-winstyle="modern" style="min-height:36px;'+(curWinStyle==='modern'?'border:1px solid rgba(255,255,255,.48);background:rgba(255,255,255, calc(var(--ph-frost-panel-a, .45) + .03));':'')+'">';
      shopH += '<span style="margin-right:8px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));">'+_roomUiIcon('window')+'</span>';
      shopH += '<div style="flex:1;"><div style="font-size:12px;font-weight:500;">现代落地窗</div></div>';
      shopH += (curWinStyle==='modern'?'<span style="font-size:10px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));font-weight:600;opacity:.8;">当前</span>':'<span class="mapActCost">$100</span>');
      shopH += '</div>';
      shopH += '<div style="height:8px;border-bottom:1px solid rgba(0,0,0,.06);margin-bottom:8px;"></div>';

      // ====== 出售区 ======
      var sellable = furniture.filter(function(f3){ return f3.owned && (FURNITURE_CATALOG[f3.type]||{}).cost > 0; });
      if(sellable.length){
        shopH += '<div style="font-size:11px;font-weight:600;color:var(--ph-icon-inner-tint,var(--ph-text-sub));margin:4px 0 4px;display:flex;align-items:center;gap:6px;">'+_roomUiIcon('money')+'<span>出售家具</span></div>';
        shopH += '<div style="font-size:9px;color:rgba(20,24,28,.35);margin-bottom:6px;">⏰ 购买不超过1天原价退款，超过1天8折出售</div>';
        sellable.forEach(function(sf){
          var sc = FURNITURE_CATALOG[sf.type]||{};
          var dayMs = 24*60*60*1000;
          var isWithinDay = sf.boughtAt && (Date.now() - sf.boughtAt < dayMs);
          var sellPrice = isWithinDay ? sc.cost : Math.floor(sc.cost * 0.8);
          var _slbl = sc.label;
          if(sc.styles && sc.styles.length && sf.styleId){
            var _ss = sc.styles.find(function(s2){return s2.id===sf.styleId;});
            if(_ss) _slbl += ' · '+_ss.label;
          }
          shopH += '<div class="mapActRow" data-act="shopSell" data-furnid="'+sf.id+'" data-sellprice="'+sellPrice+'">';
          shopH += '<span style="margin-right:8px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));">'+_roomUiIcon(sf.type||sc.emoji)+'</span>';
          shopH += '<div style="flex:1;"><div style="font-size:13px;font-weight:500;">'+_slbl+'</div><div style="font-size:10px;color:rgba(180,80,80,.6);">'+(isWithinDay?'原价退款':'8折出售')+'</div></div>';
          shopH += '<span class="mapActCost">+$'+sellPrice+'</span>';
          shopH += '</div>';
        });
        shopH += '<div style="height:8px;border-bottom:1px solid rgba(0,0,0,.06);margin-bottom:8px;"></div>';
      }

      // ====== 购买区 ======
      shopH += '<div style="font-size:11px;font-weight:600;color:rgba(20,24,28,.5);margin:4px 0 4px;display:flex;align-items:center;gap:6px;">'+_roomUiIcon('plus')+'<span>购买新家具</span></div>';
      var ownedTypes = furniture.filter(function(f3){return f3.owned;}).map(function(f3){return f3.type;});
      for(var ck in FURNITURE_CATALOG){
        var cc = FURNITURE_CATALOG[ck];
        if(cc.cost <= 0) continue;
        var alreadyOwned = ownedTypes.indexOf(ck) >= 0;
        shopH += '<div class="mapActRow" data-act="shopBuy" data-ftype="'+ck+'" style="'+(alreadyOwned?'opacity:0.4;pointer-events:none;':'')+'">';
        shopH += '<span style="margin-right:8px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));">'+_roomUiIcon(ck||cc.emoji)+'</span>';
        shopH += '<div style="flex:1;"><div style="font-size:13px;font-weight:500;">'+cc.label+(cc.styles&&cc.styles.length>1?' <span style=\'font-size:9px;color:#888;\'>('+cc.styles.length+'款)</span>':'')+'</div><div style="font-size:10px;color:rgba(20,24,28,.4);">'+cc.desc+'</div></div>';
        shopH += '<span class="mapActCost">'+(alreadyOwned?'已拥有':'$'+cc.cost)+'</span>';
        shopH += '</div>';
      }
      shopH += '<button data-act="shopClose" style="width:100%;padding:10px;border-radius:10px;border:1px solid rgba(0,0,0,.08);background:#fff;font-size:13px;cursor:pointer;margin-top:8px;">关闭</button>';
      var shopOv = _cpShowOverlay(shopH);
      shopOv.addEventListener('click', function(ev2){
        var t2 = ev2.target.closest('[data-act]');
        if(!t2) return;
        if(t2.getAttribute('data-act')==='shopClose'){ shopOv.remove(); return; }

        // === 窗户款式 ===
        if(t2.getAttribute('data-act')==='winStyle'){
          var ws = t2.getAttribute('data-winstyle');
          if(ws === house._windowStyle || (!house._windowStyle && ws==='default')){ return; }
          if(ws === 'modern' && house._windowStyle !== 'modern'){
            if(!_roomCanAfford(100)){ try{toast('💰 '+(npcOwner?esc(npcOwnerName)+'余额不足':'余额不足'));}catch(e){} return; }
            _roomSpend(100, '窗户装修：现代落地窗');
          }
          house._windowStyle = ws;
          // 切换款式时重置窗户位置，避免位置错乱
          house._winLeft = {ox:75, oy:50, sc:1};
          house._winRight = {ox:225, oy:68, sc:1};
          _mapSave(mapData);
          shopOv.remove();
          try{ toast('🪟 窗户已更换'); }catch(e){}
          renderRoom();
          return;
        }

        // === 出售 ===
        if(t2.getAttribute('data-act')==='shopSell'){
          var sellId = t2.getAttribute('data-furnid');
          var sellP = parseInt(t2.getAttribute('data-sellprice'))||0;
          var sellIdx = -1;
          for(var si=0;si<furniture.length;si++){ if(furniture[si].id===sellId){ sellIdx=si; break; } }
          if(sellIdx<0) return;
          var sellCat = FURNITURE_CATALOG[furniture[sellIdx].type]||{};
          shopOv.remove();
          var cfmH = '<div style="font-size:14px;font-weight:600;margin-bottom:8px;">确认出售</div>';
          cfmH += '<div style="font-size:12px;color:rgba(20,24,28,.6);margin-bottom:12px;display:flex;align-items:center;gap:6px;flex-wrap:wrap;">'+_roomUiIcon((furniture[sellIdx]&&furniture[sellIdx].type)||sellCat.emoji)+'<span>确定出售 '+(sellCat.label||'')+' 获得 <b style="color:var(--ph-icon-inner-tint,var(--ph-text-sub));">$'+sellP+'</b> ？</span></div>';
          cfmH += '<div style="display:flex;gap:8px;">';
          cfmH += '<button data-act="cfmCancel" style="flex:1;padding:10px;border-radius:10px;border:1px solid rgba(0,0,0,.08);background:#fff;font-size:13px;cursor:pointer;">取消</button>';
          cfmH += '<button data-act="cfmOk" style="flex:1;padding:10px;border-radius:10px;border:none;background:#e74c3c;color:#fff;font-size:13px;cursor:pointer;font-weight:600;">确认出售</button>';
          cfmH += '</div>';
          var cfmOv = _cpShowOverlay(cfmH);
          cfmOv.addEventListener('click', function(evC){
            var tc = evC.target.closest('[data-act]');
            if(!tc) return;
            if(tc.getAttribute('data-act')==='cfmCancel'){ cfmOv.remove(); return; }
            if(tc.getAttribute('data-act')==='cfmOk'){
              furniture.splice(sellIdx, 1);
              house.rooms.furniture = furniture;
              if(npcOwner){
                // 出售归还给角色余额
                if(!mapData.npcBalances) mapData.npcBalances = {};
                if(mapData.npcBalances[npcOwner] == null) mapData.npcBalances[npcOwner] = 3000;
                mapData.npcBalances[npcOwner] += sellP;
              } else {
                walletEarn(sellP, '出售家具：'+(sellCat.label||''));
              }
              _mapSave(mapData);
              cfmOv.remove();
              try{ toast('💰 已出售，获得 $'+sellP); }catch(e){}
              renderRoom();
            }
          });
          return;
        }

        // === 购买 ===
        if(t2.getAttribute('data-act')==='shopBuy'){
          var ft = t2.getAttribute('data-ftype');
          var cc2 = FURNITURE_CATALOG[ft];
          if(!cc2) return;
          if(!_roomCanAfford(cc2.cost)){ try{toast('💰 '+(npcOwner?esc(npcOwnerName)+'余额不足':'余额不足'));}catch(e){} return; }
          if(cc2.styles && cc2.styles.length > 1){
            shopOv.remove();
            var stH = '<div style="font-size:14px;font-weight:600;margin-bottom:8px;">🎨 选择款式 — '+cc2.label+'</div>';
            stH += '<div style="font-size:11px;color:rgba(20,24,28,.4);margin-bottom:10px;">共 '+cc2.styles.length+' 款 · $'+cc2.cost+'</div>';
            cc2.styles.forEach(function(st){
              stH += '<div class="mapActRow" data-act="stylePick" data-ftype="'+ft+'" data-styleid="'+st.id+'" style="min-height:44px;">';
              if(st.png && st.png.length > 10){
                stH += '<img src="'+st.png+'" style="width:36px;height:36px;object-fit:contain;margin-right:8px;border-radius:4px;background:rgba(0,0,0,.03);"/>';
              } else {
                stH += '<span style="margin-right:8px;color:var(--ph-icon-inner-tint,var(--ph-text-sub));">'+_roomUiIcon(ft||cc2.emoji)+'</span>';
              }
              stH += '<div style="flex:1;"><div style="font-size:13px;font-weight:500;">'+st.label+'</div></div>';
              stH += '<span class="mapActCost">$'+cc2.cost+'</span>';
              stH += '</div>';
            });
            stH += '<button data-act="styleCancel" style="width:100%;padding:10px;border-radius:10px;border:1px solid rgba(0,0,0,.08);background:#fff;font-size:13px;cursor:pointer;margin-top:8px;">返回</button>';
            var stOv = _cpShowOverlay(stH);
            stOv.addEventListener('click', function(ev3){
              var t3 = ev3.target.closest('[data-act]');
              if(!t3) return;
              if(t3.getAttribute('data-act')==='styleCancel'){ stOv.remove(); return; }
              if(t3.getAttribute('data-act')==='stylePick'){
                var cc3 = FURNITURE_CATALOG[t3.getAttribute('data-ftype')];
                if(!cc3) return;
                if(!_roomCanAfford(cc3.cost)){ try{toast('💰 '+(npcOwner?esc(npcOwnerName)+'余额不足':'余额不足'));}catch(e){} return; }
                _roomSpend(cc3.cost, '购买家具：'+cc3.label);
                furniture.push({ id:t3.getAttribute('data-ftype')+'_'+Date.now(), type:t3.getAttribute('data-ftype'), gx:0, gy:0, owned:true, styleId:t3.getAttribute('data-styleid'), boughtAt:Date.now() });
                house.rooms.furniture = furniture;
                _mapSave(mapData);
                stOv.remove();
                try{ toast('🎉 已购买 '+cc3.emoji+' '+cc3.label); }catch(e){}
                renderRoom();
              }
            });
            return;
          }
          _roomSpend(cc2.cost, '购买家具：'+cc2.label);
          furniture.push({ id:ft+'_'+Date.now(), type:ft, gx:0, gy:0, owned:true, boughtAt:Date.now() });
          house.rooms.furniture = furniture;
          _mapSave(mapData);
          shopOv.remove();
          try{ toast('🎉 已购买 '+cc2.emoji+' '+cc2.label); }catch(e){}
          renderRoom();
        }
      });
      return;
    }
  });

  // Hide map zoom bar while room is open
  var _mapZoomBar = container.querySelector('.mapZoomBar');
  if(_mapZoomBar) _mapZoomBar.style.display = 'none';

  container.appendChild(roomEl);

  // ★ 把房间标题注入顶部 AppBar，让全局「‹」按钮关闭房间
  try{
    var _titleEl = root.querySelector('[data-ph="appTitle"]');
    if(_titleEl) _titleEl.textContent = house.name;
    var _spEl = root.querySelector('.phAppBarSpacer');
    if(_spEl){
      if(npcOwner){
        _spEl.innerHTML = '<button class="phBarRBtn" data-act="roomSettings" title="房间设置" style="font-size:16px;display:flex;align-items:center;justify-content:center;">'+_roomUiIcon('settings')+'</button>';
      } else {
        _spEl.innerHTML = '';
      }
    }
  }catch(e){}

  // 拦截全局 back 动作 + app bar 按钮（gear在spacer里，在roomEl外）
  function _roomGlobalBackHook(e){
    var t = e.target && e.target.closest ? e.target.closest('[data-act]') : null;
    if(!t) return;
    var a = t.getAttribute('data-act');
    if(a === 'roomSettings'){
      _openRoomSettings(container, mapData, houseId, npcOwner, npcOwnerName);
      return;
    }
    if(a !== 'back') return;
    if(!root.contains(roomEl)) return;
    e.stopPropagation();
    clearInterval(_lightTimer);
    if(_mapZoomBar) _mapZoomBar.style.display = '';
    roomEl.remove();
    // 恢复地图标题和右侧按钮
    try{
      var _titleEl2 = root.querySelector('[data-ph="appTitle"]');
      if(_titleEl2) _titleEl2.textContent = '地图';
      var _spEl2 = root.querySelector('.phAppBarSpacer');
      if(_spEl2) _spEl2.innerHTML = '';
    }catch(e2){}
    root.removeEventListener('click', _roomGlobalBackHook, true);
  }
  root.addEventListener('click', _roomGlobalBackHook, true);
}


// ---- 地图设置弹窗（参考论坛设置） ----
function _openMapFeedSettings(){
  var af = getAutofeedCfg();
  var on = af.autoTargets && af.autoTargets.map;
  var mc = _phLoad('map_settings_v1', { logCount:3, autoGenNpc:true });
  var logData = _mapLoadLog();
  var logCount = _safeArr(logData.logs).length;

  var h = '';
  h += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;"><span style="font-size:13px;color:var(--ph-text);">参与自动运行</span><button class="sToggle'+(on?' on':'')+'" data-afm-tgt="map" style="flex-shrink:0;"></button></div>';
  h += '<div style="font-weight:600;font-size:13px;color:var(--ph-text);margin-bottom:8px;">NPC 活动日志</div>';
  h += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;"><span style="font-size:12px;color:var(--ph-text-sub);">每次生成条数</span><input data-afm-val="logCount" type="number" min="1" max="10" value="'+(mc.logCount||3)+'" style="width:60px;padding:4px 8px;border-radius:8px;border:1px solid var(--ph-glass-border);background:var(--ph-glass);color:var(--ph-text);font-size:12px;text-align:center;"/></div>';
  h += '<div style="font-size:11px;color:var(--ph-text-dim);margin-bottom:10px;">当前已有 '+logCount+' 条日志</div>';
  h += '<button data-act="mapManualGenLogs" style="width:100%;padding:10px;border:1px solid rgba(255,255,255,.46);border-radius:10px;background:rgba(255,255,255, calc(var(--ph-frost-panel-a, .45) + .03));color:var(--ph-icon-inner-tint,var(--ph-text));font-size:13px;font-weight:600;cursor:pointer;margin-bottom:10px;backdrop-filter:blur(calc(var(--ph-glass-blur,18px) * .58)) saturate(116%);-webkit-backdrop-filter:blur(calc(var(--ph-glass-blur,18px) * .58)) saturate(116%);display:flex;align-items:center;justify-content:center;gap:6px;">'+_phFlatIcon('🔄')+'<span>立即生成 NPC 活动日志</span></button>';
  h += '<div style="font-weight:600;font-size:13px;color:var(--ph-text);margin:8px 0;">高级</div>';
  h += '<textarea data-afm-ta="customPrompt" placeholder="自定义提示词补充（留空使用默认）" style="width:100%;min-height:50px;padding:8px;border-radius:10px;border:1px solid var(--ph-glass-border);background:var(--ph-glass);color:var(--ph-text);font-size:12px;resize:vertical;box-sizing:border-box;">'+(mc.customPrompt||'')+'</textarea>';
  h += '<div style="margin-top:16px;border-top:1px solid var(--ph-glass-border);padding-top:12px;"><button data-act="mapClearLogs" style="width:100%;padding:10px;border:1px solid rgba(255,255,255,.46);border-radius:10px;background:rgba(255,255,255, calc(var(--ph-frost-panel-a, .45) + .03));color:var(--ph-icon-inner-tint,var(--ph-text-sub));font-size:13px;font-weight:600;cursor:pointer;backdrop-filter:blur(calc(var(--ph-glass-blur,18px) * .58)) saturate(116%);-webkit-backdrop-filter:blur(calc(var(--ph-glass-blur,18px) * .58)) saturate(116%);display:flex;align-items:center;justify-content:center;gap:6px;">'+_phFlatIcon('🗑')+'<span>清空所有活动日志</span></button></div>';

  var modal = _afModal('地图设置', h);

  // 手动生成日志
  modal.querySelector('[data-act="mapManualGenLogs"]')?.addEventListener('click', function(){
    _mapGenerateNpcLogs({isManual:true});
    modal.remove();
    try{ toast('🗺️ 正在生成 NPC 活动日志…'); }catch(e){}
  });

  // 清空日志
  modal.querySelector('[data-act="mapClearLogs"]')?.addEventListener('click', function(){
    _mapSaveLog({ v:1, lastAutoGen:0, logs:[] });
    modal.remove();
    try{ toast('日志已清空'); }catch(e){}
  });

  // 保存设置
  var logCountInput = modal.querySelector('[data-afm-val="logCount"]');
  if(logCountInput) logCountInput.addEventListener('change', function(){
    mc.logCount = parseInt(logCountInput.value) || 3;
    _phSave('map_settings_v1', mc);
  });
  var promptInput = modal.querySelector('[data-afm-ta="customPrompt"]');
  if(promptInput) promptInput.addEventListener('change', function(){
    mc.customPrompt = promptInput.value;
    _phSave('map_settings_v1', mc);
  });

  _afBindModal(modal, 'map');
}

// ---- NPC 活动日志生成 ----
async function _mapGenerateNpcLogs(opts){
  try{
    var mapData = _mapLoad();
    if(!mapData || !mapData.generated) return;
    var logData = _mapLoadLog();
    var mc = _phLoad('map_settings_v1', { logCount:3 });
    var count = mc.logCount || 3;

    // 获取联系人列表
    var db = loadContactsDB();
    var contacts = _safeArr(db.list).slice(0, 8);
    if(!contacts.length){ try{toast('暂无联系人，无法生成日志');}catch(e){} return; }

    // 获取地标列表
    var lmNames = (mapData.landmarks||[]).map(function(lm){
      return (lm.customName||lm.name) + '(' + lm.emoji + ')';
    }).join('、');

    // 时段
    var hour = new Date().getHours();
    var period = hour < 11 ? 'morning' : (hour < 17 ? 'afternoon' : 'evening');
    var periodCN = { morning:'上午', afternoon:'下午', evening:'晚上' }[period];

    // 构建角色列表（含属性快照）
    var npcList = contacts.map(function(c){
      var s = '';
      try{ var st = catchUpStats(c.id); if(st.attrs) s = '（精力:'+Math.round(st.attrs.energy||0)+' 心情:'+Math.round(st.attrs.mood||0)+' 饱腹:'+Math.round(st.attrs.hunger||0)+'）'; }catch(e){}
      return '- '+(c.name||'?')+s;
    }).join('\n');

    var sysPrompt = '你是虚拟小镇「'+esc(mapData.name)+'」的生活模拟器。只返回 JSON 数组，不要任何其他内容或 markdown。\n格式：[{"name":"角色名","landmark":"地标名","action":"具体行为（20字内）","cost":数字}]\n其中 cost 为消费金额（0-50的整数）。action 要具体生动，如"在咖啡厅点了拿铁"。';

    var userMsg = '当前时段：'+periodCN+'。\n小镇地标：'+lmNames+'。\n角色列表：\n'+npcList+'\n\n请为其中 '+Math.min(count, contacts.length)+' 个角色各生成一条活动日志。'+
      (mc.customPrompt ? '\n补充要求：'+mc.customPrompt : '');

    var result = await PhoneAI.chat({
      system: sysPrompt,
      messages: [{ role:'user', content: userMsg }],
      maxTokens: 800,
      temperature: 0.85,
      channel: 'background',
      timeout: 45
    });

    if(!result || !result.ok) throw new Error(result ? (result.error||'AI请求失败') : 'AI请求失败');

    // 解析结果
    var raw = String(result.data || '').trim().replace(/```json[\s\S]*?```|```[\s\S]*?```/g, function(m){ return m.replace(/```json?/,'').replace(/```/,''); }).trim();
    var jsonMatch = raw.match(/\[[\s\S]*\]/);
    if(!jsonMatch) throw new Error('AI未返回JSON数组');

    var parsed = JSON.parse(jsonMatch[0]);
    if(!Array.isArray(parsed) || !parsed.length) throw new Error('解析结果为空');

    var now = Date.now();
    var added = 0;
    parsed.forEach(function(item){
      if(!item.name || !item.action) return;
      var contact = contacts.find(function(c){ return c.name === item.name; });
      var lm = (mapData.landmarks||[]).find(function(l){ return (l.customName||l.name) === item.landmark; });
      logData.logs.push({
        id: 'log_'+now+'_'+Math.random().toString(36).substr(2,4),
        npcId: contact ? contact.id : item.name,
        npcName: item.name,
        landmarkId: lm ? lm.id : '',
        time: now + Math.floor(Math.random()*60000),
        period: period,
        action: item.action,
        cost: Math.max(0, parseInt(item.cost)||0),
        statusEffect: { mood: Math.floor(Math.random()*8)+2, money: -(Math.max(0,parseInt(item.cost)||0)) },
        isAuto: !(opts && opts.isManual)
      });
      added++;
    });

    // 限制日志总量
    if(logData.logs.length > 200) logData.logs = logData.logs.slice(-200);
    logData.lastAutoGen = now;
    _mapSaveLog(logData);

    try{ toast('🗺️ 已生成 '+added+' 条活动日志'); }catch(e){}
  }catch(e){
    console.error('[Map] NPC log gen error:', e);
    try{ toast('日志生成失败: '+(e.message||String(e))); }catch(e2){}
  }
}

function _buildMapPromptBlock(npcId){
  try{
    var mapData = _mapLoad();
    if(!mapData || !mapData.generated) return '';
    var lines = ['【地图环境：'+esc(mapData.name)+'】'];

    // 全部地标列表（让 AI 知道可用名称）
    var allLmList = (mapData.landmarks||[]).map(function(lm){
      return (lm.emoji||'📍')+(lm.customName||lm.name);
    });
    if(allLmList.length) lines.push('小镇地标：'+allLmList.join('、'));

    // 住所
    if(mapData.myHouseId){
      var _mh = (mapData.houses||[]).find(function(h){ return h.id===mapData.myHouseId; });
      if(_mh) lines.push('用户的家：🏠'+_mh.name);
    }
    if(mapData.npcHouses && mapData.npcHouses[npcId]){
      var _nh = (mapData.houses||[]).find(function(h){ return h.id===mapData.npcHouses[npcId]; });
      if(_nh) lines.push('你自己的家：🏡'+_nh.name);
    }

    // 告知 AI 可以发位置
    lines.push('你可以在消息中写 [发位置:地标名] 来分享某个地标，地标名必须完全匹配上面列出的名称。');

    // 当前场景（如果从地图触发了线下场景）
    var scene = _loadSceneData(npcId);
    if(scene && scene.name){
      var lm = (mapData.landmarks||[]).find(function(l){ return (l.customName||l.name)===scene.name; });
      if(lm){
        lines.push('当前所在地标：'+scene.name+'（'+lm.emoji+'）');
        if(lm.tags) lines.push('环境氛围：'+lm.tags.slice(0,3).join('、'));
      }
    }

    // 最近去过的地标
    var allVisits = [];
    (mapData.landmarks||[]).forEach(function(lm2){
      (lm2.visits||[]).forEach(function(v){
        if(v.npcId===npcId) allVisits.push({ name:lm2.customName||lm2.name, time:v.time, actionId:v.actionId });
      });
    });
    allVisits.sort(function(a,b){ return b.time-a.time; });
    var recent = allVisits.slice(0,3);
    if(recent.length){
      lines.push('最近去过：'+recent.map(function(r){ return r.name; }).join('、'));
    }

    // NPC活动日志
    var logData = _mapLoadLog();
    var npcLogs = _safeArr(logData.logs).filter(function(l){ return l.npcId===npcId; }).slice(-3).reverse();
    if(npcLogs.length){
      lines.push('角色近期活动：');
      npcLogs.forEach(function(l){
        var lmName = '';
        var lm3 = (mapData.landmarks||[]).find(function(m){ return m.id===l.landmarkId; });
        if(lm3) lmName = lm3.customName || lm3.name;
        lines.push('- '+esc(l.action||'')+(lmName?' (在'+lmName+')':''));
      });
    }

    // 钱包余额
    try{
      var w = loadWallet();
      if(w) lines.push('用户当前金币余额：'+w.balance);
    }catch(e){}

    return lines.length > 1 ? lines.join('\n') : '';
  }catch(e){ return ''; }
}
